ogTerm = term.current()\\r\\\
\\r\\\
function buildMenu()\\r\\\
	 title = \\\"Installed Manuals (/etc/man)\\\"\\r\\\
	 choices = {}\\r\\\
	choices[1] = \\\"return/exit\\\"\\r\\\
	 actions = {}\\r\\\
	actions[1] = function()\\r\\\
		minux.debug(\\\"softmenu:return/exit\\\" , \\\"minux\\\")\\r\\\
		manmenuactive = false\\r\\\
	end\\r\\\
-- here we build the menu\\r\\\
	local appcount = 1\\r\\\
	local listcount = 2\\r\\\
