		term.setTextColor(colortable[3])\\r\\\
		local title = \\\"Minux V:\\\".._G.version..\\\" U-\\\".._G.login\\r\\\
		print(title..string.rep(\\\" \\\", termX - #title))\\r\\\
		print(string.rep(\\\" \\\", termX))\\r\\\
		term.redirect(baseTerm)\\r\\\
