    [ \"etc/apt/boot/minux-main.d\" ] = \"-- 3rd party addon launcher\\r\\\
-- minux autocomplete function script\\r\\\
completion = require \\\"cc.shell.completion\\\"\\r\\\
complete = completion.build( { completion.file, many = true })\\r\\\
completecfg = completion.build({ completion.choice, { \\\"clearlogin\\\",\\\"mapcleanup\\\",\\\"login\\\", \\\"update\\\", \\\"menu\\\", \\\"debug\\\", \\\"ui\\\",\\\"welcome\\\", \\\"network\\\", \\\"crashhandler\\\", \\\"encrypt\\\" } })\\r\\\
completeapt = completion.build({ completion.choice, { \\\"install\\\", \\\"-i\\\", \\\"remove\\\",\\\"-r\\\", \\\"update\\\",\\\"-u\\\", \\\"forceupdate\\\",\\\"-U\\\", \\\"list-installed\\\",\\\"-l\\\",\\\"list-available\\\",\\\"-la\\\",\\\"list-source\\\",\\\"-ls\\\",\\\"setsource\\\",\\\"-s\\\", \\\"clearsource\\\",\\\"-c\\\" } })\\r\\\
