end\\\
minux.debug(\\\"ecpw:done\\\",\\\"minux\\\")\\\
\",\
    [ \"etc/man/apt.man\" ] = \"APT-inspired by debian's\\\
apt system\\\
\\\
executable location: \\\
'/bin/apt.sh' \\\
alias: 'apt'\\\
apt is part of the \\\
'minux-main' app\\\
\\\
apt is used to manage \\\
software packages,be it\\\
install, remove, update\\\
\\\
it keeps a list of the \\\
software installed on \\\
the machine and uses \\\
this to knowwhat apps \\\
and associated files \\\
to fetch.\\\
\\\
syntax: \\\
'apt command app'\\\
\\\
command parameters: \\\
-l : 'list' , \\\
lists all installed \\\
software\\\
\\\
-i : 'install', \\\
install an app\\\
\\\
-r : 'remove', \\\
remove an app\\\
\\\
-u : 'update', updates \\\
an app, if no app name \\\
is provided update all.\\\
\\\
-U : 'forced update', \\\
force update all.\\\
\\\
-s : 'source' ,sets an \\\
additional repo source\\\
\\\
-c : 'source\\\" \\\
clears an apt source\\\
\\\
-ls : lists currently \\\
active apt sources\\\
\\\
-la : lists available \\\
software on apt sources\\\
\\\
-a : 'autoupdate' sets \\\
automatic updates\\\
\\\
-i and -r require you \\\
are logged in as an\\\
admin/owner, -u and -U \\\
work for every user.\\\
apt will refuse to work\\\
if no user is logged in\\\
\\\
to install an app, use \\\
the -i option, \\\
eg: 'apt -i tron' will \\\
install the 'tron' app.\\\
\\\
important locations:\\\
/etc/apt/list - keeps \\\
the .db files of what \\\
app	is installed and \\\
what files are linked.\\\
changing the list .db \\\
files allows you to\\\
manually edit what \\\
programs are installed\\\
on the machine, in case \\\
of corruption.\\\
\\\
/etc/apt/version -keeps\\\
 the version files.\\\
changing these files \\\
will alter the known\\\
version and trigger an \\\
update for that program \\\
when 'apt -u' is used.\\\
	\\\
/usr/apt/source.ls - \\\
apt source file\\\
this file containts the\\\
apt repository sources, \\\
you can delete the ones \\\
you don't want\",\
    [ \"etc/man/man.man\" ] = \"man - a manual reader \\\
\\\
executable location: \\\
'/bin/man.sh' \\\
alias:'man'\\\
man is part of the \\\
'minux-main' app\\\
\\\
man is used to open \\\
manuals.\\\
\\\
syntax: 'man appname'\\\
\\\
 - list\\\
if list is provided in \\\
stead of an app name,\\\
man will display a list\\\
 of all it's known apps\\\
\\\
important locations:\\\
/etc/man - location of \\\
the manuals\",\
    [ \"ubin/configfile.sh\" ] = \"-- example of a user shortcut.\\\
-- files placed in this location can be created by users, making shortcuts that display in the menu to.\\\
-- in this case, we are simply telling edit to open the settings file, but you could add any lua code in here\\\
\\\
shell.run(\\\"/bin/edit.sh /usr/minux-main/settings.cfg\\\")\\\
\",\
    [ \"bin/usermod.sh\" ] = \"args = {...}\\\
action = args[1]\\\
etc1 = args[2]\\\
etc2 = args[3]\\\
etc3 = args[4]\\\
\\\
if _G.admin ~= true then \\\
	print(\\\"Access denied!\\\")\\\
	return 0 \\\
end\\\
\\\
if fs.exists(\\\"/usr/minux-main/settings.cfg\\\") == false then\\\
	print(\\\"configuration files missing, run 'login set local/network'\\\")\\\
else\\\
	local authtype = minux.getconfig(\\\"login\\\")\\\
	if authtype == \\\"local\\\" then\\\
		if action == \\\"?\\\" or action == \\\"help\\\" then\\\
			print(\\\"/bin/usermod.sh\\\")\\\
			print(\\\"usage: 'usermod action arg1 arg2'\\\")\\\
			print(\\\"eg: usermod add testuser testpassword\\\")\\\
			print(\\\"eg2: usermod del testuser\\\")\\\
			print(\\\"eg3: usermod psw testuser testpass\\\")\\\
			print(\\\"options:\\\")\\\
			print(\\\"add, del, resetpass\\\")\\\
			return 0\\\
		elseif action == \\\"add\\\" then\\\
			if fs.exists(\\\"/usr/local/auth/\\\"..etc1..\\\".usr\\\") then\\\
				print(\\\"this user already exists\\\")\\\
				return 0\\\
			else\\\
				file = fs.open(\\\"/usr/local/auth/\\\"..etc1..\\\".usr\\\" , \\\"w\\\")\\\
				local encrypt = minux.getconfig(\\\"encrypt\\\")\\\
				if encrypt == true then\\\
					local keyfile = fs.open(\\\"/usr/minux-main/config/encr.conf\\\",\\\"r\\\")\\\
					local tempkey = keyfile.readLine()\\\
					local key = tonumber(tempkey)\\\
					keyfile.close()\\\
					etc2 = minux.encrypt(etc2, key)\\\
				end\\\
				file.write(etc2)\\\
				file.close()\\\
				print(\\\"user added!\\\")\\\
			end\\\
		elseif action == \\\"del\\\" then\\\
			if fs.exists(\\\"/usr/local/auth/\\\"..etc1..\\\".usr\\\") == false then\\\
				print(\\\"this user does not exists\\\")\\\
				return 0\\\
			elseif etc1 == \\\"root\\\" then\\\
				print(\\\"you cannot delete root\\\")\\\
			else\\\
				file = fs.delete(\\\"/usr/local/auth/\\\"..etc1..\\\".usr\\\")\\\
				print(\\\"user removed!\\\")\\\
			end\\\
		elseif action == \\\"psw\\\" then\\\
			if fs.exists(\\\"/usr/local/auth/\\\"..etc1..\\\".usr\\\") == false then\\\
				print(\\\"this user does not exists\\\")\\\
				return 0\\\
			else \\\
				file = fs.open(\\\"/usr/local/auth/\\\"..etc1..\\\".usr\\\" , \\\"w\\\")\\\
				local encrypt = minux.getconfig(\\\"encrypt\\\")\\\
				if encrypt == true then\\\
					local keyfile = fs.open(\\\"/usr/minux-main/config/encr.conf\\\",\\\"r\\\")\\\
					local tempkey = keyfile.readLine()\\\
					local key = tonumber(tempkey)\\\
					keyfile.close()\\\
					etc2 = minux.encrypt(etc2,key)\\\
				end\\\
				file.write(etc2)\\\
				file.close()\\\
				print(\\\"user modified\\\")\\\
			end\\\
		else\\\
			print(\\\"invalid data, use 'usermod ?'\\\")\\\
			return 0\\\
		end\\\
	else\\\
	print(\\\"authentication type is not set to local\\\")\\\
	print(\\\"use 'auth-client' to manage networked users\\\")\\\
	print(\\\"use 'apt -i auth-client' to install said package\\\")\\\
	end\\\
end\\\
\",\
    [ \"etc/minux-main/sys/dcpw.sys\" ] = \"local key = 0\\\
minux.debug(\\\"dcpw:start\\\",\\\"minux\\\")\\\
local keyfile = fs.open(\\\"/usr/minux-main/config/encr.conf\\\",\\\"r\\\")\\\
local tempkey = keyfile.readLine()\\\
local key = tonumber(tempkey)\\\
keyfile.close()\\\
minux.debug(\\\"dcpw:done\\\" , \\\"minux\\\")\\\
minux.lsr(\\\"/usr/local/auth/\\\")\\\
local tempfile = fs.open(\\\"/temp/ls/files.ls\\\",\\\"r\\\")\\\
local nus = tempfile.readLine()\\\
while nus ~= nil do\\\
    minux.debug(\\\"dcpw:\\\"..nus,\\\"minux\\\")\\\
    local editfile = fs.open(nus,\\\"r\\\")\\\
    local tmpdata = editfile.readLine()\\\
    editfile.close()\\\
    local newdata = minux.decrypt(tmpdata,key)\\\
    local editfile = fs.open(nus,\\\"w\\\")\\\
    editfile.writeLine(newdata)\\\
    editfile.close()\\\
    nus = tempfile.readLine()\\\
end\\\
minux.debug(\\\"dcpw:done\\\",\\\"minux\\\")\\\
\",\
    [ \"etc/minux-main/sys/shedit.sys\" ] = \"-- Lex & ShEdit, by LoganDark\\r\\\
-- Permission to edit and redistribute on oc.cil.li:\\r\\\
-- https://oc.cil.li/topic/1495-shedit-editlua-but-with-syntax-highlighting/?do=findComment&comment=8526\\r\\\
-- \\\" Feel free to use it in its current state though, or modify/improve it! \\\"\\r\\\
\\r\\\
-- Can be loaded using os.loadAPI, has only a single function: lex('code here')\\r\\\
-- If loaded using dofile(), it returns the lex function (for environments outside ComputerCraft)\\r\\\
-- It returns a list of lists, where each list is one line.\\r\\\
-- Each line contains tokens (in the order they are found), where each token is formatted like this:\\r\\\
-- {\\r\\\
--  type = one of the token types below,\\r\\\
--  data = the source code that makes up the token,\\r\\\
--  posFirst = the position (inclusive) within THAT LINE that the token starts\\r\\\
--  posLast = the position (inclusive) within THAT LINE that the token ends\\r\\\
-- }\\r\\\
\\r\\\
-- Possible token types:\\r\\\
--  whitespace: Self-explanatory. Can match spaces, newlines, tabs, and carriage returns (although I don't know why anyone would use those... WINDOWS)\\r\\\
--  comment: Either multi-line or single-line comments.\\r\\\
--  string: A string. Usually the part of the string that is not an escape.\\r\\\
--  escape: Can only be found within strings (although they are separate tokens)\\r\\\
--  keyword: Keywords. Like \\\"while\\\", \\\"end\\\", \\\"do\\\", etc\\r\\\
--  value: Special values. Only true, false, and nil.\\r\\\
--  ident: Identifier. Variables, function names, etc..\\r\\\
--  number: Numbers!\\r\\\
--  symbol: Symbols, like brackets, parenthesis, ., .., ... etc\\r\\\
--  operator: Operators, like =, ==, >=, <=, ~=, etc\\r\\\
--  unidentified: Anything that isn't one of the above tokens. Consider them ERRORS.\\r\\\
\\r\\\
-- minux team adjustment: removed \\\"keys.rightAlt\\\" for AZERTY keyboard compatibility.\\r\\\
\\r\\\
local chars = {\\r\\\
	whitespace = {\\r\\\
		[' '] = true,\\r\\\
