			['C'] = true,\\r\\\
			['D'] = true,\\r\\\
			['E'] = true,\\r\\\
			['F'] = true,\\r\\\
			['G'] = true,\\r\\\
			['H'] = true,\\r\\\
			['I'] = true,\\r\\\
			['J'] = true,\\r\\\
			['K'] = true,\\r\\\
			['L'] = true,\\r\\\
