\\r\\\
		hex = {\\r\\\
			['0'] = true,\\r\\\
			['1'] = true,\\r\\\
			['2'] = true,\\r\\\
			['3'] = true,\\r\\\
			['4'] = true,\\r\\\
			['5'] = true,\\r\\\
			['6'] = true,\\r\\\
			['7'] = true,\\r\\\
			['8'] = true,\\r\\\
			['9'] = true,\\r\\\
			['a'] = true,\\r\\\
			['b'] = true,\\r\\\
			['c'] = true,\\r\\\
			['d'] = true,\\r\\\
			['e'] = true,\\r\\\
			['f'] = true,\\r\\\
			['A'] = true,\\r\\\
			['B'] = true,\\r\\\
			['C'] = true,\\r\\\
			['D'] = true,\\r\\\
			['E'] = true,\\r\\\
			['F'] = true\\r\\\
		}\\r\\\
	},\\r\\\
\\r\\\
	symbols = {\\r\\\
		['+'] = true,\\r\\\
		['-'] = true,\\r\\\
		['*'] = true,\\r\\\
		['/'] = true,\\r\\\
		['^'] = true,\\r\\\
		['%'] = true,\\r\\\
		[','] = true,\\r\\\
		['{'] = true,\\r\\\
		['}'] = true,\\r\\\
		['['] = true,\\r\\\
		[']'] = true,\\r\\\
		['('] = true,\\r\\\
		[')'] = true,\\r\\\
		[';'] = true,\\r\\\
		['#'] = true,\\r\\\
		['.'] = true,\\r\\\
		[':'] = true,\\r\\\
\\r\\\
		equality = {\\r\\\
			['~'] = true,\\r\\\
			['='] = true,\\r\\\
			['>'] = true,\\r\\\
			['<'] = true\\r\\\
		},\\r\\\
\\r\\\
		operators = {\\r\\\
			['+'] = true,\\r\\\
			['-'] = true,\\r\\\
			['*'] = true,\\r\\\
			['/'] = true,\\r\\\
			['^'] = true,\\r\\\
			['%'] = true,\\r\\\
			['#'] = true\\r\\\
		}\\r\\\
	}\\r\\\
}\\r\\\
\\r\\\
local keywords = {\\r\\\
	structure = {\\r\\\
		['and'] = true,\\r\\\
		['break'] = true,\\r\\\
		['do'] = true,\\r\\\
		['else'] = true,\\r\\\
		['elseif'] = true,\\r\\\
		['end'] = true,\\r\\\
		['for'] = true,\\r\\\
		['function'] = true,\\r\\\
		['goto'] = true,\\r\\\
		['if'] = true,\\r\\\
		['in'] = true,\\r\\\
		['local'] = true,\\r\\\
		['not'] = true,\\r\\\
		['or'] = true,\\r\\\
		['repeat'] = true,\\r\\\
		['return'] = true,\\r\\\
		['then'] = true,\\r\\\
		['until'] = true,\\r\\\
		['while'] = true\\r\\\
	},\\r\\\
\\r\\\
	values = {\\r\\\
		['true'] = true,\\r\\\
		['false'] = true,\\r\\\
		['nil'] = true\\r\\\
	}\\r\\\
}\\r\\\
\\r\\\
function lex(text)\\r\\\
	local pos = 1\\r\\\
	local start = 1\\r\\\
	local len = #text\\r\\\
	local buffer = {}\\r\\\
	local lines = {}\\r\\\
\\r\\\
	local function look(delta)\\r\\\
		delta = pos + (delta or 0)\\r\\\
\\r\\\
		return text:sub(delta, delta)\\r\\\
	end\\r\\\
\\r\\\
	local function get()\\r\\\
		local char = text:sub(pos, pos)\\r\\\
\\r\\\
		pos = pos + 1\\r\\\
\\r\\\
		return char\\r\\\
	end\\r\\\
\\r\\\
	local function getLevel()\\r\\\
		local num = 0\\r\\\
\\r\\\
		while look(num) == '=' do\\r\\\
			num = num + 1\\r\\\
		end\\r\\\
\\r\\\
		if look(num) == '[' then\\r\\\
			pos = pos + num\\r\\\
\\r\\\
			return num\\r\\\
		else\\r\\\
			return nil\\r\\\
		end\\r\\\
	end\\r\\\
\\r\\\
	local function getToken()\\r\\\
		return text:sub(start, pos - 1)\\r\\\
	end\\r\\\
\\r\\\
	local currentLineLength = 0\\r\\\
	local lineoffset = 0\\r\\\
\\r\\\
	local function token(type, text)\\r\\\
		local tk = buffer[#buffer]\\r\\\
\\r\\\
		if not tk or tk.type ~= type then\\r\\\
			local tk = {\\r\\\
				type = type,\\r\\\
				data = text or getToken(),\\r\\\
				posFirst = start - lineoffset,\\r\\\
				posLast = pos - 1 - lineoffset\\r\\\
			}\\r\\\
\\r\\\
			if tk.data ~= '' then\\r\\\
				buffer[#buffer + 1] = tk\\r\\\
			end\\r\\\
		else\\r\\\
			tk.data = tk.data .. (text or getToken())\\r\\\
			tk.posLast = tk.posFirst + #tk.data - 1\\r\\\
			--tk.posLast = getCol(pos - 1)\\r\\\
		end\\r\\\
\\r\\\
		currentLineLength = currentLineLength + (text or getToken()):len()\\r\\\
\\r\\\
		start = pos\\r\\\
		return tk\\r\\\
	end\\r\\\
\\r\\\
	local function newline()\\r\\\
		lines[#lines + 1] = buffer\\r\\\
		buffer = {}\\r\\\
		get()\\r\\\
		token('newline')\\r\\\
		buffer[1] = nil\\r\\\
		lineoffset = lineoffset + currentLineLength\\r\\\
		currentLineLength = 0\\r\\\
	end\\r\\\
\\r\\\
	local function getData(level, type)\\r\\\
		while true do\\r\\\
			local char = get()\\r\\\
\\r\\\
			if char == '' then\\r\\\
				return\\r\\\
			elseif char == '\\\\n' then\\r\\\
				pos = pos - 1\\r\\\
				token(type)\\r\\\
				newline()\\r\\\
			elseif char == ']' then\\r\\\
				local valid = true\\r\\\
\\r\\\
				for i = 1, level do\\r\\\
					if look() == '=' then\\r\\\
						pos = pos + 1\\r\\\
					else\\r\\\
						valid = false\\r\\\
						break\\r\\\
					end\\r\\\
				end\\r\\\
\\r\\\
				if valid and look() == ']' then\\r\\\
					pos = pos + 1\\r\\\
\\r\\\
					return\\r\\\
				end\\r\\\
			end\\r\\\
		end\\r\\\
	end\\r\\\
\\r\\\
	while true do\\r\\\
		while true do\\r\\\
			local char = look()\\r\\\
\\r\\\
			if char == '\\\\n' then\\r\\\
				token('whitespace')\\r\\\
				newline()\\r\\\
			elseif chars.whitespace[char] then\\r\\\
				pos = pos + 1\\r\\\
			else\\r\\\
				break\\r\\\
			end\\r\\\
		end\\r\\\
\\r\\\
		token('whitespace')\\r\\\
\\r\\\
		local char = get()\\r\\\
\\r\\\
		if char == '' then\\r\\\
			break\\r\\\
		elseif char == '-' and look() == '-' then\\r\\\
			pos = pos + 1\\r\\\
\\r\\\
			if look() == '[' then\\r\\\
				pos = pos + 1\\r\\\
\\r\\\
				local level = getLevel()\\r\\\
\\r\\\
				if level then\\r\\\
					getData(level, 'comment')\\r\\\
				else\\r\\\
					while true do\\r\\\
						local char2 = get()\\r\\\
\\r\\\
						if char2 == '' or char2 == '\\\\n' then\\r\\\
							pos = pos - 1\\r\\\
							token('comment')\\r\\\
\\r\\\
							if char2 == '\\\\n' then\\r\\\
								newline()\\r\\\
							end\\r\\\
\\r\\\
							break\\r\\\
						end\\r\\\
					end\\r\\\
				end\\r\\\
			else\\r\\\
				while true do\\r\\\
					local char2 = get()\\r\\\
\\r\\\
					if char2 == '' or char2 == '\\\\n' then\\r\\\
						pos = pos - 1\\r\\\
						token('comment')\\r\\\
\\r\\\
						if char2 == '\\\\n' then\\r\\\
							newline()\\r\\\
						end\\r\\\
\\r\\\
						break\\r\\\
					end\\r\\\
				end\\r\\\
			end\\r\\\
\\r\\\
			token('comment')\\r\\\
		elseif char == '\\\\'' or char == '\\\"' then\\r\\\
			while true do\\r\\\
				local char2 = get()\\r\\\
\\r\\\
				if char2 == '\\\\\\\\' then\\r\\\
					pos = pos - 1\\r\\\
					token('string')\\r\\\
					get()\\r\\\
\\r\\\
					local char3 = get()\\r\\\
\\r\\\
					if chars.digits[char3] then\\r\\\
						for i = 1, 2 do\\r\\\
							if chars.digits[look()] then\\r\\\
								pos = pos + 1\\r\\\
							end\\r\\\
						end\\r\\\
					elseif char3 == 'x' then\\r\\\
						if chars.digits.hex[look()] and chars.digits.hex[look(1)] then\\r\\\
							pos = pos + 2\\r\\\
						else\\r\\\
							token('unidentified')\\r\\\
						end\\r\\\
					elseif char3 == '\\\\n' then\\r\\\
						pos = pos - 1\\r\\\
						token('escape')\\r\\\
						newline()\\r\\\
					elseif not chars.validEscapes[char3] then\\r\\\
                        token('unidentified')\\r\\\
					end\\r\\\
\\r\\\
					token('escape')\\r\\\
				elseif char2 == '\\\\n' then\\r\\\
					pos = pos - 1\\r\\\
					token('string')\\r\\\
					newline()\\r\\\
\\r\\\
					break\\r\\\
				elseif char2 == char or char2 == '' then\\r\\\
					break\\r\\\
				end\\r\\\
			end\\r\\\
\\r\\\
			token('string')\\r\\\
		elseif chars.ident.start[char] then\\r\\\
			while chars.ident[look()] do\\r\\\
				pos = pos + 1\\r\\\
			end\\r\\\
\\r\\\
			local word = getToken()\\r\\\
\\r\\\
			if keywords.structure[word] then\\r\\\
				token('keyword')\\r\\\
			elseif keywords.values[word] then\\r\\\
				token('value')\\r\\\
			else\\r\\\
				token('ident')\\r\\\
			end\\r\\\
		elseif chars.digits[char] or (char == '.' and chars.digits[look()]) then\\r\\\
			if char == '0' and look() == 'x' then\\r\\\
				pos = pos + 1\\r\\\
\\r\\\
				while chars.digits.hex[look()] do\\r\\\
					pos = pos + 1\\r\\\
				end\\r\\\
			else\\r\\\
				while chars.digits[look()] do\\r\\\
					pos = pos + 1\\r\\\
				end\\r\\\
\\r\\\
				if look() == '.' then\\r\\\
					pos = pos + 1\\r\\\
\\r\\\
					while chars.digits[look()] do\\r\\\
						pos = pos + 1\\r\\\
					end\\r\\\
				end\\r\\\
\\r\\\
				if look():lower() == 'e' then\\r\\\
					pos = pos + 1\\r\\\
\\r\\\
					if look() == '-' then\\r\\\
						pos = pos + 1\\r\\\
					end\\r\\\
\\r\\\
					while chars.digits[look()] do\\r\\\
						pos = pos + 1\\r\\\
					end\\r\\\
				end\\r\\\
			end\\r\\\
\\r\\\
			token('number')\\r\\\
		elseif char == '[' then\\r\\\
			local level = getLevel()\\r\\\
\\r\\\
			if level then\\r\\\
				getData(level, 'string')\\r\\\
				token('string')\\r\\\
			else\\r\\\
				token('symbol')\\r\\\
			end\\r\\\
		elseif char == '.' then\\r\\\
			if look() == '.' then\\r\\\
				pos = pos + 1\\r\\\
\\r\\\
				if look() == '.' then\\r\\\
					pos = pos + 1\\r\\\
				end\\r\\\
			end\\r\\\
\\r\\\
			token('symbol')\\r\\\
		elseif chars.symbols.equality[char] then\\r\\\
			if look() == '=' then\\r\\\
				pos = pos + 1\\r\\\
			end\\r\\\
\\r\\\
			token('operator')\\r\\\
		elseif chars.symbols[char] then\\r\\\
			if chars.symbols.operators[char] then\\r\\\
				token('operator')\\r\\\
			else\\r\\\
				token('symbol')\\r\\\
			end\\r\\\
		else\\r\\\
			token('unidentified')\\r\\\
		end\\r\\\
	end\\r\\\
\\r\\\
	lines[#lines + 1] = buffer\\r\\\
\\r\\\
	return lines\\r\\\
end\\r\\\
\\r\\\
-- Get file to edit\\r\\\
local tArgs = { ... }\\r\\\
if #tArgs == 0 then\\r\\\
	print( \\\"Usage: shedit <path>\\\" )\\r\\\
	return\\r\\\
end\\r\\\
\\r\\\
-- Error checking\\r\\\
local sPath = shell.resolve( tArgs[1] )\\r\\\
local bReadOnly = fs.isReadOnly( sPath )\\r\\\
if fs.exists( sPath ) and fs.isDir( sPath ) then\\r\\\
	print( \\\"Cannot edit a directory.\\\" )\\r\\\
	return\\r\\\
end\\r\\\
\\r\\\
local x,y = 1,1\\r\\\
