\\r\\\
-- Colors\\r\\\
local highlightColor, keywordColor, commentColor, textColor, bgColor, stringColor\\r\\\
if term.isColor() then\\r\\\
	bgColor = colors.black\\r\\\
	textColor = colors.white\\r\\\
	highlightColor = colors.yellow\\r\\\
	keywordColor = colors.yellow\\r\\\
	commentColor = colors.green\\r\\\
	stringColor = colors.red\\r\\\
else\\r\\\
	bgColor = colors.black\\r\\\
	textColor = colors.white\\r\\\
	highlightColor = colors.white\\r\\\
	keywordColor = colors.white\\r\\\
	commentColor = colors.white\\r\\\
	stringColor = colors.white\\r\\\
