\\r\\\
-- Menus\\r\\\
local bMenu = false\\r\\\
local nMenuItem = 1\\r\\\
local tMenuItems = {}\\r\\\
if not bReadOnly then\\r\\\
	table.insert( tMenuItems, \\\"Save\\\" )\\r\\\
end\\r\\\
if shell.openTab then\\r\\\
	table.insert( tMenuItems, \\\"Run\\\" )\\r\\\
end\\r\\\
if peripheral.find( \\\"printer\\\" ) then\\r\\\
	table.insert( tMenuItems, \\\"Print\\\" )\\r\\\
end\\r\\\
table.insert( tMenuItems, \\\"Exit\\\" )\\r\\\
table.insert(tMenuItems, 'Tools')\\r\\\
table.insert(tMenuItems, 'Find')\\r\\\
table.insert(tMenuItems, 'Jump')\\r\\\
table.insert(tMenuItems, 'Copy')\\r\\\
table.insert(tMenuItems, 'VPaste')\\r\\\
\\r\\\
local sStatus = \\\"Press Ctrl to access menu\\\"\\r\\\
if string.len( sStatus ) > w - 5 then\\r\\\
	sStatus = \\\"Press Ctrl for menu\\\"\\r\\\
end\\r\\\
\\r\\\
local function load( _sPath )\\r\\\
	tLines = {}\\r\\\
	if fs.exists( _sPath ) then\\r\\\
		local file = io.open( _sPath, \\\"r\\\" )\\r\\\
		local sLine = file:read()\\r\\\
		while sLine do\\r\\\
			table.insert( tLines, sLine )\\r\\\
			sLine = file:read()\\r\\\
		end\\r\\\
		file:close()\\r\\\
	end\\r\\\
\\r\\\
	if #tLines == 0 then\\r\\\
		table.insert( tLines, \\\"\\\" )\\r\\\
	end\\r\\\
end\\r\\\
\\r\\\
local function save( _sPath )\\r\\\
	-- Create intervening folder\\r\\\
	local sDir = _sPath:sub(1, _sPath:len() - fs.getName(_sPath):len() )\\r\\\
	if not fs.exists( sDir ) then\\r\\\
		fs.makeDir( sDir )\\r\\\
	end\\r\\\
\\r\\\
	-- Save\\r\\\
	local file = nil\\r\\\
	local function innerSave()\\r\\\
		file = fs.open( _sPath, \\\"w\\\" )\\r\\\
		if file then\\r\\\
			for n, sLine in ipairs( tLines ) do\\r\\\
				file.write( sLine .. \\\"\\\\n\\\" )\\r\\\
			end\\r\\\
		else\\r\\\
			error( \\\"Failed to open \\\".._sPath )\\r\\\
		end\\r\\\
	end\\r\\\
\\r\\\
	local ok, err = pcall( innerSave )\\r\\\
	if file then\\r\\\
		file.close()\\r\\\
	end\\r\\\
	return ok, err\\r\\\
end\\r\\\
\\r\\\
local tKeywords = {\\r\\\
	[\\\"and\\\"] = true,\\r\\\
	[\\\"break\\\"] = true,\\r\\\
	[\\\"do\\\"] = true,\\r\\\
	[\\\"else\\\"] = true,\\r\\\
	[\\\"elseif\\\"] = true,\\r\\\
	[\\\"end\\\"] = true,\\r\\\
	[\\\"false\\\"] = true,\\r\\\
	[\\\"for\\\"] = true,\\r\\\
	[\\\"function\\\"] = true,\\r\\\
	[\\\"if\\\"] = true,\\r\\\
	[\\\"in\\\"] = true,\\r\\\
	[\\\"local\\\"] = true,\\r\\\
	[\\\"nil\\\"] = true,\\r\\\
	[\\\"not\\\"] = true,\\r\\\
	[\\\"or\\\"] = true,\\r\\\
	[\\\"repeat\\\"] = true,\\r\\\
	[\\\"return\\\"] = true,\\r\\\
	[\\\"then\\\"] = true,\\r\\\
	[\\\"true\\\"] = true,\\r\\\
	[\\\"until\\\"]= true,\\r\\\
	[\\\"while\\\"] = true,\\r\\\
}\\r\\\
\\r\\\
local function tryWrite( sLine, regex, color )\\r\\\
	local match = string.match( sLine, regex )\\r\\\
	if match then\\r\\\
		if type(color) == \\\"number\\\" then\\r\\\
			term.setTextColor( color )\\r\\\
		else\\r\\\
			term.setTextColor( color(match) )\\r\\\
		end\\r\\\
		term.write( match )\\r\\\
		term.setTextColor( textColor )\\r\\\
		return string.sub( sLine, string.len(match) + 1 )\\r\\\
	end\\r\\\
	return nil\\r\\\
end\\r\\\
\\r\\\
--[[local function writeHighlighted( sLine )\\r\\\
	while string.len(sLine) > 0 do\\r\\\
		sLine =\\r\\\
			tryWrite( sLine, \\\"^%-%-%[%[.-%]%]\\\", commentColor ) or\\r\\\
			tryWrite( sLine, \\\"^%-%-.*\\\", commentColor ) or\\r\\\
			tryWrite( sLine, \\\"^\\\\\\\"\\\\\\\"\\\", stringColor ) or\\r\\\
			tryWrite( sLine, \\\"^\\\\\\\".-[^\\\\\\\\]\\\\\\\"\\\", stringColor ) or\\r\\\
			tryWrite( sLine, \\\"^\\\\'\\\\'\\\", stringColor ) or\\r\\\
			tryWrite( sLine, \\\"^\\\\'.-[^\\\\\\\\]\\\\'\\\", stringColor ) or\\r\\\
			tryWrite( sLine, \\\"^%[%[.-%]%]\\\", stringColor ) or\\r\\\
			tryWrite( sLine, \\\"^[%w_]+\\\", function( match )\\r\\\
				if tKeywords[ match ] then\\r\\\
					return keywordColor\\r\\\
				end\\r\\\
				return textColor\\r\\\
			end ) or\\r\\\
			tryWrite( sLine, \\\"^[^%w_]\\\", textColor )\\r\\\
	end\\r\\\
end]]\\r\\\
