\\r\\\
local function onUpdate()\\r\\\
	tokenized = lex(table.concat(tLines, '\\\\n'))\\r\\\
end\\r\\\
\\r\\\
local function markExists()\\r\\\
	if markX ~= x or markY ~= y then\\r\\\
		return true\\r\\\
	else\\r\\\
		return false\\r\\\
	end\\r\\\
end\\r\\\
\\r\\\
local function isMarked(newX, newY)\\r\\\
	if (newY > markY and newY < y) or (newY > y and newY < markY) then\\r\\\
		return true\\r\\\
	end\\r\\\
\\r\\\
	if newY == markY and newY == y then\\r\\\
		if markX > x and newX >= x and newX < markX then\\r\\\
			return true\\r\\\
		elseif markX < x and newX >= markX and newX < x then\\r\\\
			return true\\r\\\
		end\\r\\\
	elseif newY == markY then\\r\\\
		if newX < markX and y < markY then\\r\\\
			return true\\r\\\
		elseif newX >= markX and y > markY then\\r\\\
			return true\\r\\\
		end\\r\\\
	elseif newY == y then\\r\\\
		if newX < x and y > markY then\\r\\\
			return true\\r\\\
		elseif newX >= x and y < markY then\\r\\\
			return true\\r\\\
		end\\r\\\
	end\\r\\\
\\r\\\
	return false\\r\\\
end\\r\\\
\\r\\\
local function getMarks()\\r\\\
	local msx, msy\\r\\\
	local mex, mey\\r\\\
\\r\\\
	if markY == y then\\r\\\
		if markX > x then\\r\\\
			msx = x\\r\\\
			msy = y\\r\\\
			mex = markX\\r\\\
			mey = markY\\r\\\
		else\\r\\\
			msx = markX\\r\\\
			msy = markY\\r\\\
			mex = x\\r\\\
			mey = y\\r\\\
		end\\r\\\
	else\\r\\\
		if markY > y then\\r\\\
			msx = x\\r\\\
			msy = y\\r\\\
			mex = markX\\r\\\
			mey = markY\\r\\\
		else\\r\\\
			msx = markX\\r\\\
			msy = markY\\r\\\
			mex = x\\r\\\
			mey = y\\r\\\
		end\\r\\\
	end\\r\\\
\\r\\\
	return msx, msy, mex, mey\\r\\\
end\\r\\\
\\r\\\
local function getCharDisplay(char)\\r\\\
	if char == '\\\\t' then\\r\\\
		return '    '\\r\\\
	else\\r\\\
		return char\\r\\\
	end\\r\\\
end\\r\\\
\\r\\\
local function getCharWidth(char)\\r\\\
	return getCharDisplay(char):len()\\r\\\
end\\r\\\
\\r\\\
local function writeHighlighted(lineNr)\\r\\\
	local tokens = tokenized[lineNr] or {}\\r\\\
	local textColor = term.getTextColor()\\r\\\
	local bgColor = term.getBackgroundColor()\\r\\\
	local setX, setY = term.getCursorPos()\\r\\\
	local msx, msy, mex, mey = getMarks()\\r\\\
\\r\\\
	if lineNr < mey and lineNr >= msy then\\r\\\
		term.setBackgroundColor(colors.white)\\r\\\
	end\\r\\\
\\r\\\
	term.clearLine()\\r\\\
	term.setCursorPos(setX, setY)\\r\\\
\\r\\\
	for t = 1, #tokens do\\r\\\
		local token = tokens[t]\\r\\\
		local color = colors.white\\r\\\
\\r\\\
		if token.type == 'keyword' or token.type == 'operator' then\\r\\\
			color = colors.yellow\\r\\\
		elseif token.type == 'number' or token.type == 'value' then\\r\\\
			color = colors.purple\\r\\\
		elseif token.type == 'comment' then\\r\\\
			color = colors.green\\r\\\
		elseif token.type == 'ident' and apis[token.data] then\\r\\\
			color = colors.lightGray\\r\\\
		elseif token.type == 'string' then\\r\\\
			color = colors.cyan\\r\\\
		elseif token.type == 'escape' then\\r\\\
			color = colors.purple\\r\\\
		elseif token.type == 'unidentified' then\\r\\\
			color = colors.red\\r\\\
		end\\r\\\
\\r\\\
		for p = 1, #token.data do\\r\\\
			local sub = getCharDisplay(token.data:sub(p, p))\\r\\\
\\r\\\
			local cX, cY = p + token.posFirst - 1, lineNr\\r\\\
\\r\\\
			if (cY == msy and cY == mey and cX >= msx and cX < mex) or (cY == msy and cY ~= mey and cX >= msx) or (cY == mey and cY ~= msy and cX < mex) or (cY > msy and cY < mey) then\\r\\\
				term.setTextColor(colors.black)\\r\\\
				term.setBackgroundColor(color)\\r\\\
			else\\r\\\
				term.setBackgroundColor(colors.black)\\r\\\
				term.setTextColor(color)\\r\\\
			end\\r\\\
\\r\\\
			term.write(sub)\\r\\\
		end\\r\\\
	end\\r\\\
\\r\\\
	term.setTextColor(textColor)\\r\\\
	term.setBackgroundColor(bgColor)\\r\\\
end\\r\\\
\\r\\\
local tCompletions\\r\\\
local nCompletion\\r\\\
\\r\\\
local tCompleteEnv = _ENV\\r\\\
local function complete( sLine )\\r\\\
	if settings.get( \\\"edit.autocomplete\\\" ) then\\r\\\
		local nStartPos = string.find( sLine, \\\"[a-zA-Z0-9_%.]+$\\\" )\\r\\\
		if nStartPos then\\r\\\
			sLine = string.sub( sLine, nStartPos )\\r\\\
		end\\r\\\
		if #sLine > 0 then\\r\\\
			return textutils.complete( sLine, tCompleteEnv )\\r\\\
		end\\r\\\
	end\\r\\\
	return nil\\r\\\
end\\r\\\
\\r\\\
local function recomplete()\\r\\\
	local sLine = tLines[y]\\r\\\
	if not bMenu and not bReadOnly and x == string.len(sLine) + 1 then\\r\\\
		tCompletions = complete( sLine )\\r\\\
		if tCompletions and #tCompletions > 0 then\\r\\\
			nCompletion = 1\\r\\\
		else\\r\\\
			nCompletion = nil\\r\\\
		end\\r\\\
	else\\r\\\
		tCompletions = nil\\r\\\
		nCompletion = nil\\r\\\
	end\\r\\\
end\\r\\\
\\r\\\
local function writeCompletion( sLine )\\r\\\
	if nCompletion then\\r\\\
		local sCompletion = tCompletions[ nCompletion ]\\r\\\
		term.setTextColor( colors.white )\\r\\\
		term.setBackgroundColor( colors.gray )\\r\\\
		term.write( sCompletion )\\r\\\
		term.setTextColor( textColor )\\r\\\
		term.setBackgroundColor( bgColor )\\r\\\
	end\\r\\\
end\\r\\\
\\r\\\
local function getCursorX(lineNr)\\r\\\
	local line = tLines[lineNr]\\r\\\
	local cx = 1\\r\\\
\\r\\\
	for i = 1, x - 1 do\\r\\\
		cx = cx + getCharWidth(line:sub(i, i))\\r\\\
	end\\r\\\
\\r\\\
	return cx\\r\\\
end\\r\\\
\\r\\\
local function cxToPos(lineNr, cx)\\r\\\
	local line = tLines[lineNr]\\r\\\
	local num = 1\\r\\\
	local pos = 1\\r\\\
\\r\\\
	for i = 1, #line do\\r\\\
		amt = getCharWidth(line:sub(i, i))\\r\\\
\\r\\\
		if num + amt > cx then\\r\\\
			return pos\\r\\\
		else\\r\\\
			num = num + amt\\r\\\
			pos = pos + 1\\r\\\
		end\\r\\\
	end\\r\\\
\\r\\\
	return pos\\r\\\
end\\r\\\
\\r\\\
local function redrawText()\\r\\\
	local cursorX, cursorY = x, y\\r\\\
	for y=1,h-1 do\\r\\\
		term.setCursorPos( 1 - scrollX, y )\\r\\\
		term.clearLine()\\r\\\
\\r\\\
		local sLine = tLines[ y + scrollY ]\\r\\\
		if sLine ~= nil then\\r\\\
			--writeHighlighted( sLine )\\r\\\
			writeHighlighted(y + scrollY)\\r\\\
			if cursorY == y + scrollY and cursorX == #sLine + 1 then\\r\\\
				writeCompletion()\\r\\\
			end\\r\\\
		end\\r\\\
	end\\r\\\
\\r\\\
	local cx = getCursorX(y)\\r\\\
\\r\\\
	term.setCursorPos( cx - scrollX, y - scrollY )\\r\\\
end\\r\\\
\\r\\\
--[[local function redrawLine(_nY)\\r\\\
	local sLine = tLines[_nY]\\r\\\
	if sLine then\\r\\\
		term.setCursorPos( 1 - scrollX, _nY - scrollY )\\r\\\
		term.clearLine()\\r\\\
		--writeHighlighted( sLine )\\r\\\
		writeHighlighted(_nY)\\r\\\
		if _nY == y and x == #sLine + 1 then\\r\\\
			writeCompletion()\\r\\\
		end\\r\\\
		term.setCursorPos( x - scrollX, _nY - scrollY )\\r\\\
	end\\r\\\
end]]\\r\\\
\\r\\\
local redrawLine = redrawText\\r\\\
\\r\\\
local function redrawMenu()\\r\\\
	-- Clear line\\r\\\
	term.setCursorPos( 1, h )\\r\\\
	term.clearLine()\\r\\\
\\r\\\
	-- Draw line numbers\\r\\\
	--[[term.setCursorPos( w - string.len( \\\"Ln \\\"..y ) + 1, h )\\r\\\
	term.setTextColor( highlightColor )\\r\\\
	term.write( \\\"Ln \\\" )\\r\\\
	term.setTextColor( textColor )\\r\\\
	term.write( y )]]\\r\\\
\\r\\\
	if not bMenu then\\r\\\
		-- Draw status\\r\\\
		term.setTextColor( highlightColor )\\r\\\
		term.write( sStatus )\\r\\\
		term.setTextColor( textColor )\\r\\\
\\r\\\
		term.setCursorPos(w - ('[' .. x .. ':' .. y .. ']:[' .. markX .. ':' .. markY .. ']'):len() + 1, h)\\r\\\
		term.setTextColor(highlightColor)\\r\\\
		term.write('[')\\r\\\
		term.setTextColor(textColor)\\r\\\
		term.write(x)\\r\\\
		term.setTextColor(highlightColor)\\r\\\
		term.write(':')\\r\\\
		term.setTextColor(textColor)\\r\\\
		term.write(y)\\r\\\
		term.setTextColor(highlightColor)\\r\\\
		term.write(']:[')\\r\\\
		term.setTextColor(textColor)\\r\\\
		term.write(markX)\\r\\\
		term.setTextColor(highlightColor)\\r\\\
		term.write(':')\\r\\\
		term.setTextColor(textColor)\\r\\\
		term.write(markY)\\r\\\
		term.setTextColor(highlightColor)\\r\\\
		term.write(']')\\r\\\
		term.setTextColor(textColor)\\r\\\
	else\\r\\\
		-- Draw menu\\r\\\
		term.setTextColor( textColor )\\r\\\
		for nItem,sItem in pairs( tMenuItems ) do\\r\\\
			if nItem == nMenuItem then\\r\\\
				term.setTextColor( highlightColor )\\r\\\
				term.write( \\\"[\\\" )\\r\\\
				term.setTextColor( textColor )\\r\\\
				term.write( sItem )\\r\\\
				term.setTextColor( highlightColor )\\r\\\
				term.write( \\\"]\\\" )\\r\\\
				term.setTextColor( textColor )\\r\\\
			else\\r\\\
				term.write( \\\" \\\"..sItem..\\\" \\\" )\\r\\\
			end\\r\\\
		end\\r\\\
	end\\r\\\
\\r\\\
	-- Reset cursor\\r\\\
	term.setCursorPos( getCursorX(y) - scrollX, y - scrollY )\\r\\\
end\\r\\\
\\r\\\
local function setCursor( newX, newY )\\r\\\
	local oldX, oldY = x, y\\r\\\
	x, y = newX, newY\\r\\\
	local screenX = getCursorX(y) - scrollX\\r\\\
	local screenY = y - scrollY\\r\\\
\\r\\\
	local bRedraw = false\\r\\\
	if screenX < 1 then\\r\\\
		scrollX = getCursorX(y) - 1\\r\\\
		screenX = 1\\r\\\
		bRedraw = true\\r\\\
	elseif screenX > w then\\r\\\
		scrollX = scrollX + (screenX - w)\\r\\\
		screenX = w\\r\\\
		bRedraw = true\\r\\\
	end\\r\\\
\\r\\\
	if screenY < 1 then\\r\\\
		scrollY = y - 1\\r\\\
		screenY = 1\\r\\\
		bRedraw = true\\r\\\
	elseif screenY > h-1 then\\r\\\
		scrollY = y - (h-1)\\r\\\
		screenY = h-1\\r\\\
		bRedraw = true\\r\\\
	end\\r\\\
\\r\\\
	recomplete()\\r\\\
	if bRedraw then\\r\\\
		redrawText()\\r\\\
	elseif y ~= oldY then\\r\\\
		redrawLine( oldY )\\r\\\
		redrawLine( y )\\r\\\
	else\\r\\\
		redrawLine( y )\\r\\\
	end\\r\\\
	term.setCursorPos( screenX, screenY )\\r\\\
\\r\\\
	redrawMenu()\\r\\\
end\\r\\\
\\r\\\
local function setCursorMark(newX, newY)\\r\\\
	markX, markY = newX, newY\\r\\\
	setCursor(newX, newY)\\r\\\
end\\r\\\
\\r\\\
local function deleteMarked()\\r\\\
	if markExists() then\\r\\\
		local msx, msy, mex, mey = getMarks()\\r\\\
\\r\\\
		if msy == mey then\\r\\\
			local line = tLines[mey]\\r\\\
\\r\\\
			tLines[mey] = line:sub(1, msx - 1) .. line:sub(mex)\\r\\\
		else\\r\\\
			if mey - msy > 1 then\\r\\\
				for i = 1, mey - msy - 1 do\\r\\\
					table.remove(tLines, msy + 1)\\r\\\
				end\\r\\\
			end\\r\\\
\\r\\\
			local line = tLines[msy]\\r\\\
			local line2 = tLines[msy + 1]\\r\\\
\\r\\\
			tLines[msy] = line:sub(1, msx - 1) .. line2:sub(mex)\\r\\\
			table.remove(tLines, msy + 1)\\r\\\
		end\\r\\\
\\r\\\
		setCursorMark(msx, msy)\\r\\\
	end\\r\\\
end\\r\\\
\\r\\\
local function getMarked()\\r\\\
	if markExists() then\\r\\\
		local msx, msy, mex, mey = getMarks()\\r\\\
\\r\\\
		if msy == mey then\\r\\\
			return tLines[msy]:sub(msx, mex - 1)\\r\\\
		else\\r\\\
			local marked = tLines[msy]:sub(msx)\\r\\\
\\r\\\
			if mey - msy > 1 then\\r\\\
				for i = msy + 1, mey - 1 do\\r\\\
					marked = marked .. '\\\\n' .. tLines[i]\\r\\\
				end\\r\\\
			end\\r\\\
\\r\\\
			marked = marked .. '\\\\n' .. tLines[mey]:sub(1, mex - 1)\\r\\\
\\r\\\
			return marked\\r\\\
		end\\r\\\
	end\\r\\\
end\\r\\\
\\r\\\
local toolsFuncs = {\\r\\\
	{\\r\\\
		'Convert 2 spaces to tabs',\\r\\\
		function()\\r\\\
			for i = 1, #tLines do\\r\\\
				local line = tLines[i]\\r\\\
				local count = 0\\r\\\
\\r\\\
				while true do\\r\\\
					if line:sub(count * 2 + 1, count * 2 + 2) == '  ' then\\r\\\
						count = count + 1\\r\\\
					else\\r\\\
						break\\r\\\
					end\\r\\\
				end\\r\\\
\\r\\\
				tLines[i] = ('\\\\t'):rep(count) .. line:sub(count * 2 + 1)\\r\\\
			end\\r\\\
		end\\r\\\
	}, {\\r\\\
		'Convert tabs to 2 spaces',\\r\\\
		function()\\r\\\
			for i = 1, #tLines do\\r\\\
				local line = tLines[i]\\r\\\
				local count = 0\\r\\\
\\r\\\
				while true do\\r\\\
					if line:sub(count + 1, count + 1) == '\\\\t' then\\r\\\
						count = count + 1\\r\\\
					else\\r\\\
						break\\r\\\
					end\\r\\\
				end\\r\\\
\\r\\\
				tLines[i] = ('  '):rep(count) .. line:sub(count + 1)\\r\\\
			end\\r\\\
		end\\r\\\
	}\\r\\\
}\\r\\\
\\r\\\
-- for testing scrolling, etc in the tools menu\\r\\\
--[[for i = 1, 50 do\\r\\\
	table.insert(toolsFuncs, {'Do nothing ' .. tostring(i), function() end})\\r\\\
end]]\\r\\\
\\r\\\
\\r\\\
local findHistory = {}\\r\\\
local jumpHistory = {}\\r\\\
local vClipboard = ''\\r\\\
\\r\\\
local tMenuFuncs = {\\r\\\
	Save = function()\\r\\\
		if bReadOnly then\\r\\\
			sStatus = \\\"Access denied\\\"\\r\\\
		else\\r\\\
			local ok, err = save( sPath )\\r\\\
			if ok then\\r\\\
				sStatus=\\\"Saved to \\\"..sPath\\r\\\
			else\\r\\\
				sStatus=\\\"Error saving to \\\"..sPath\\r\\\
			end\\r\\\
		end\\r\\\
		redrawMenu()\\r\\\
	end,\\r\\\
	Print = function()\\r\\\
		local printer = peripheral.find( \\\"printer\\\" )\\r\\\
		if not printer then\\r\\\
			sStatus = \\\"No printer attached\\\"\\r\\\
			return\\r\\\
		end\\r\\\
\\r\\\
		local nPage = 0\\r\\\
		local sName = fs.getName( sPath )\\r\\\
		if printer.getInkLevel() < 1 then\\r\\\
			sStatus = \\\"Printer out of ink\\\"\\r\\\
			return\\r\\\
		elseif printer.getPaperLevel() < 1 then\\r\\\
			sStatus = \\\"Printer out of paper\\\"\\r\\\
			return\\r\\\
		end\\r\\\
\\r\\\
		local screenTerminal = term.current()\\r\\\
		local printerTerminal = {\\r\\\
			getCursorPos = printer.getCursorPos,\\r\\\
			setCursorPos = printer.setCursorPos,\\r\\\
			getSize = printer.getPageSize,\\r\\\
			write = printer.write,\\r\\\
		}\\r\\\
		printerTerminal.scroll = function()\\r\\\
			if nPage == 1 then\\r\\\
				printer.setPageTitle( sName..\\\" (page \\\"..nPage..\\\")\\\" )\\r\\\
			end\\r\\\
\\r\\\
			while not printer.newPage()	do\\r\\\
				if printer.getInkLevel() < 1 then\\r\\\
					sStatus = \\\"Printer out of ink, please refill\\\"\\r\\\
				elseif printer.getPaperLevel() < 1 then\\r\\\
					sStatus = \\\"Printer out of paper, please refill\\\"\\r\\\
				else\\r\\\
					sStatus = \\\"Printer output tray full, please empty\\\"\\r\\\
				end\\r\\\
\\r\\\
				term.redirect( screenTerminal )\\r\\\
				redrawMenu()\\r\\\
				term.redirect( printerTerminal )\\r\\\
\\r\\\
				local timer = os.startTimer(0.5)\\r\\\
				sleep(0.5)\\r\\\
			end\\r\\\
\\r\\\
			nPage = nPage + 1\\r\\\
			if nPage == 1 then\\r\\\
				printer.setPageTitle( sName )\\r\\\
			else\\r\\\
				printer.setPageTitle( sName..\\\" (page \\\"..nPage..\\\")\\\" )\\r\\\
			end\\r\\\
		end\\r\\\
\\r\\\
		bMenu = false\\r\\\
		term.redirect( printerTerminal )\\r\\\
		local ok, error = pcall( function()\\r\\\
			term.scroll()\\r\\\
			for n, sLine in ipairs( tLines ) do\\r\\\
				print( sLine )\\r\\\
			end\\r\\\
		end )\\r\\\
		term.redirect( screenTerminal )\\r\\\
		if not ok then\\r\\\
			print( error )\\r\\\
		end\\r\\\
\\r\\\
		while not printer.endPage() do\\r\\\
			sStatus = \\\"Printer output tray full, please empty\\\"\\r\\\
			redrawMenu()\\r\\\
			sleep( 0.5 )\\r\\\
		end\\r\\\
		bMenu = true\\r\\\
\\r\\\
		if nPage > 1 then\\r\\\
			sStatus = \\\"Printed \\\"..nPage..\\\" Pages\\\"\\r\\\
		else\\r\\\
			sStatus = \\\"Printed 1 Page\\\"\\r\\\
		end\\r\\\
		redrawMenu()\\r\\\
	end,\\r\\\
	Exit = function()\\r\\\
		bRunning = false\\r\\\
	end,\\r\\\
	Run = function()\\r\\\
		local sTempPath = \\\"/.temp\\\"\\r\\\
		local ok, err = save( sTempPath )\\r\\\
		if ok then\\r\\\
			local nTask = shell.openTab( sTempPath )\\r\\\
			if nTask then\\r\\\
				shell.switchTab( nTask )\\r\\\
			else\\r\\\
				sStatus=\\\"Error starting Task\\\"\\r\\\
			end\\r\\\
			fs.delete( sTempPath )\\r\\\
		else\\r\\\
			sStatus=\\\"Error saving to \\\"..sTempPath\\r\\\
		end\\r\\\
		redrawMenu()\\r\\\
	end,\\r\\\
	Tools = function()\\r\\\
		bMenu = false\\r\\\
		redrawText()\\r\\\
		redrawMenu()\\r\\\
\\r\\\
		local bgColor = term.getBackgroundColor()\\r\\\
		paintutils.drawFilledBox(2, 2, w - 1, h - 1, colors.gray)\\r\\\
		term.setCursorPos(3, 3)\\r\\\
		term.write('ShEdit Tools')\\r\\\
\\r\\\
		local scrollY = 0\\r\\\
		local height = h - 8\\r\\\
		local offset = 5\\r\\\
		local selected = 1\\r\\\
		local run = false\\r\\\
\\r\\\
		term.setTextColor(colors.lightGray)\\r\\\
		term.setCursorPos(3, offset + height + 1)\\r\\\
		term.write('Arrows to select. Enter to run. Ctrl to cancel.')\\r\\\
\\r\\\
		while true do\\r\\\
			term.setBackgroundColor(colors.gray)\\r\\\
			term.setTextColor(colors.lightGray)\\r\\\
			local toWrite = '(' .. tostring(selected) .. '/' .. tostring(#toolsFuncs) .. ')'\\r\\\
			term.setCursorPos(w - toWrite:len() - 1, 3)\\r\\\
			term.write(toWrite)\\r\\\
			term.setTextColor(colors.white)\\r\\\
\\r\\\
			for i = 1, height do\\r\\\
				local index = i + scrollY\\r\\\
				term.setTextColor(colors.white)\\r\\\
\\r\\\
				if selected == index then\\r\\\
					term.setTextColor(keywordColor)\\r\\\
				end\\r\\\
\\r\\\
				if index <= #toolsFuncs then\\r\\\
					paintutils.drawLine(2, offset + i - 1, w - 1, offset + i - 1, color)\\r\\\
					term.setCursorPos(3, offset + index - scrollY - 1)\\r\\\
\\r\\\
					if selected == index then\\r\\\
						term.write('> ')\\r\\\
					else\\r\\\
						term.write('  ')\\r\\\
					end\\r\\\
\\r\\\
					term.write(toolsFuncs[index][1])\\r\\\
				end\\r\\\
			end\\r\\\
\\r\\\
			local evt, arg1, arg2, arg3 = os.pullEvent()\\r\\\
			local clampScroll = false\\r\\\
\\r\\\
			if evt == 'key' then\\r\\\
				clampScroll = true\\r\\\
\\r\\\
				if arg1 == keys.up then\\r\\\
					if selected == 1 then\\r\\\
						selected = #toolsFuncs\\r\\\
					else\\r\\\
						selected = selected - 1\\r\\\
					end\\r\\\
				elseif arg1 == keys.down then\\r\\\
					if selected == #toolsFuncs then\\r\\\
						selected = 1\\r\\\
					else\\r\\\
						selected = selected + 1\\r\\\
					end\\r\\\
				elseif arg1 == keys.pageUp then\\r\\\
					selected = math.max(1, math.min(#toolsFuncs, selected - height))\\r\\\
				elseif arg1 == keys.pageDown then\\r\\\
					selected = math.max(1, math.min(#toolsFuncs, selected + height))\\r\\\
				elseif arg1 == keys.enter then\\r\\\
					run = true\\r\\\
\\r\\\
					break\\r\\\
				elseif arg1 == keys.leftCtrl then\\r\\\
					break\\r\\\
				else\\r\\\
					clampScroll = false\\r\\\
				end\\r\\\
			elseif evt == 'mouse_click' then\\r\\\
				if arg1 == 1 then\\r\\\
					if arg2 > 1 and arg2 < w then\\r\\\
						if arg3 >= offset and arg3 < offset + height then\\r\\\
							local index = arg3 - offset + scrollY + 1\\r\\\
\\r\\\
							if index <= #toolsFuncs then\\r\\\
								selected = index\\r\\\
								run = true\\r\\\
\\r\\\
								break\\r\\\
							end\\r\\\
						end\\r\\\
					end\\r\\\
				end\\r\\\
			elseif evt == 'mouse_scroll' then\\r\\\
				if arg2 > 1 and arg2 < w then\\r\\\
					if arg3 >= offset and arg3 < offset + height then\\r\\\
						scrollY = math.max(0, math.min(#toolsFuncs - height, scrollY + arg1))\\r\\\
					end\\r\\\
				end\\r\\\
			end\\r\\\
\\r\\\
			if clampScroll == true then\\r\\\
				if selected > height + scrollY then\\r\\\
					scrollY = selected - height\\r\\\
				elseif selected <= scrollY then\\r\\\
					scrollY = selected - 1\\r\\\
				end\\r\\\
			end\\r\\\
		end\\r\\\
\\r\\\
		term.setBackgroundColor(bgColor)\\r\\\
		redrawText()\\r\\\
		bMenu = true\\r\\\
\\r\\\
		if run then\\r\\\
			if not bReadOnly then\\r\\\
				bMenu = false\\r\\\
				redrawMenu()\\r\\\
				toolsFuncs[selected][2]()\\r\\\
				onUpdate()\\r\\\
				redrawText()\\r\\\
				bMenu = true\\r\\\
			else\\r\\\
				sStatus = 'File is read-only'\\r\\\
			end\\r\\\
		end\\r\\\
	end,\\r\\\
	Find = function()\\r\\\
		term.setCursorPos(1, h)\\r\\\
		term.clearLine()\\r\\\
\\r\\\
		term.setTextColor(highlightColor)\\r\\\
		term.write('Find: ')\\r\\\
		term.setTextColor(textColor)\\r\\\
\\r\\\
		local text = read(nil, findHistory)\\r\\\
		table.insert(findHistory, text)\\r\\\
\\r\\\
		local fLine, fPos\\r\\\
		local found = false\\r\\\
\\r\\\
		for i = y, #tLines do\\r\\\
			local searchText = tLines[i]\\r\\\
\\r\\\
			if i == y then\\r\\\
				searchText = searchText:sub(x + 1)\\r\\\
			end\\r\\\
\\r\\\
			local searchPat = ''\\r\\\
\\r\\\
			local escapedChars = {\\r\\\
				['%'] = true, ['.'] = true, ['('] = true, [')'] = true,\\r\\\
				['%'] = true, ['+'] = true, ['-'] = true, ['*'] = true,\\r\\\
				['?'] = true, ['['] = true, ['^'] = true, ['$'] = true\\r\\\
			}\\r\\\
\\r\\\
			for i = 1, #text do\\r\\\
				local char = text:sub(i, i)\\r\\\
\\r\\\
				if escapedChars[char] == true then\\r\\\
					searchPat = searchPat .. '%'\\r\\\
				end\\r\\\
\\r\\\
				searchPat = searchPat .. char\\r\\\
			end\\r\\\
\\r\\\
			local pos = searchText:find(searchPat)\\r\\\
\\r\\\
			if pos then\\r\\\
				fLine = i\\r\\\
				fPos = pos\\r\\\
\\r\\\
				if i == y then\\r\\\
					fPos = fPos + x\\r\\\
				end\\r\\\
\\r\\\
				found = true\\r\\\
\\r\\\
				break\\r\\\
			end\\r\\\
		end\\r\\\
\\r\\\
		if not found then\\r\\\
			sStatus = 'Found no matches'\\r\\\
		else\\r\\\
			setCursorMark(fPos, fLine)\\r\\\
			setCursor(fPos + text:len(), fLine)\\r\\\
			sStatus = 'Found a match on line ' .. tostring(fLine)\\r\\\
		end\\r\\\
\\r\\\
		redrawText()\\r\\\
	end,\\r\\\
	Jump = function()\\r\\\
		term.setCursorPos(1, h)\\r\\\
		term.clearLine()\\r\\\
\\r\\\
		term.setTextColor(highlightColor)\\r\\\
		term.write('Jump: ')\\r\\\
		term.setTextColor(textColor)\\r\\\
\\r\\\
		local toJump = read(nil, jumpHistory)\\r\\\
		table.insert(jumpHistory, toJump)\\r\\\
\\r\\\
		local num = tonumber(toJump)\\r\\\
\\r\\\
		if not num then\\r\\\
			sStatus = 'Invalid line'\\r\\\
		else\\r\\\
			if num % 1 == 0 then\\r\\\
				if num >= 1 and num <= #tLines then\\r\\\
					setCursorMark(1, num)\\r\\\
					sStatus = 'Successfully jumped to line ' .. toJump\\r\\\
				else\\r\\\
					sStatus = 'Line is not in the range 1 - ' .. tostring(#tLines)\\r\\\
				end\\r\\\
			else\\r\\\
				sStatus = 'Line must be an integer'\\r\\\
			end\\r\\\
		end\\r\\\
\\r\\\
		redrawText()\\r\\\
	end,\\r\\\
	Copy = function()\\r\\\
		vClipboard = getMarked()\\r\\\
\\r\\\
		local lines = 1\\r\\\
\\r\\\
		for i = 1, #vClipboard do\\r\\\
			if vClipboard:sub(i, i) == '\\\\n' then\\r\\\
				lines = lines + 1\\r\\\
			end\\r\\\
		end\\r\\\
\\r\\\
		sStatus = 'Copied ' .. tostring(lines) .. ' lines'\\r\\\
	end,\\r\\\
	VPaste = function()\\r\\\
		if not bReadOnly then\\r\\\
			deleteMarked()\\r\\\
			local lines = 1\\r\\\
\\r\\\
			for i = 1, #vClipboard do\\r\\\
				local char = vClipboard:sub(i, i)\\r\\\
\\r\\\
				if char == '\\\\n' then\\r\\\
					lines = lines + 1\\r\\\
					local sLine = tLines[y]\\r\\\
					tLines[y] = string.sub(sLine,1,x-1)\\r\\\
					table.insert( tLines, y+1, string.sub(sLine,x) )\\r\\\
					x = 1\\r\\\
					y = y + 1\\r\\\
				else\\r\\\
					tLines[y] = tLines[y]:sub(1, x - 1) .. char .. tLines[y]:sub(x)\\r\\\
					x = x + 1\\r\\\
				end\\r\\\
			end\\r\\\
\\r\\\
			setCursorMark(x, y)\\r\\\
			onUpdate()\\r\\\
			redrawText()\\r\\\
\\r\\\
			sStatus = 'Pasted ' .. tostring(lines) .. ' lines'\\r\\\
		else\\r\\\
			sStatus = 'File is read-only'\\r\\\
		end\\r\\\
	end\\r\\\
}\\r\\\
\\r\\\
local function doMenuItem( _n )\\r\\\
	tMenuFuncs[tMenuItems[_n]]()\\r\\\
	if bMenu then\\r\\\
		bMenu = false\\r\\\
		term.setCursorBlink( true )\\r\\\
	end\\r\\\
	redrawMenu()\\r\\\
end\\r\\\
\\r\\\
-- Actual program functionality begins\\r\\\
load(sPath)\\r\\\
\\r\\\
term.setBackgroundColor( bgColor )\\r\\\
term.clear()\\r\\\
term.setCursorPos(getCursorX(y), y)\\r\\\
term.setCursorBlink( true )\\r\\\
\\r\\\
recomplete()\\r\\\
onUpdate()\\r\\\
redrawText()\\r\\\
redrawMenu()\\r\\\
\\r\\\
local function acceptCompletion()\\r\\\
	if nCompletion then\\r\\\
		-- Append the completion\\r\\\
		local sCompletion = tCompletions[ nCompletion ]\\r\\\
		tLines[y] = tLines[y] .. sCompletion\\r\\\
		onUpdate()\\r\\\
		setCursorMark( x + string.len( sCompletion ), y )\\r\\\
	end\\r\\\
end\\r\\\
\\r\\\
local holdingShift = false\\r\\\
\\r\\\
-- Handle input\\r\\\
while bRunning do\\r\\\
	local sEvent, param, param2, param3 = os.pullEvent()\\r\\\
	if sEvent == \\\"key\\\" then\\r\\\
		local oldX, oldY = x, y\\r\\\
		if param == keys.up then\\r\\\
			local cursorSet = setCursorMark\\r\\\
\\r\\\
			if holdingShift then\\r\\\
				cursorSet = setCursor\\r\\\
			end\\r\\\
\\r\\\
			-- Up\\r\\\
			if not bMenu then\\r\\\
				if nCompletion then\\r\\\
					-- Cycle completions\\r\\\
					nCompletion = nCompletion - 1\\r\\\
					if nCompletion < 1 then\\r\\\
						nCompletion = #tCompletions\\r\\\
					end\\r\\\
					redrawLine(y)\\r\\\
\\r\\\
				elseif y > 1 then\\r\\\
					-- Move cursor up\\r\\\
					--[[cursorSet(\\r\\\
						math.min( x, string.len( tLines[y - 1] ) + 1 ),\\r\\\
						y - 1\\r\\\
					)]]\\r\\\
\\r\\\
					local cx = getCursorX(y)\\r\\\
					local pos = cxToPos(y - 1, cx)\\r\\\
\\r\\\
					cursorSet(pos, y - 1)\\r\\\
				else\\r\\\
					cursorSet(1, y)\\r\\\
				end\\r\\\
			end\\r\\\
\\r\\\
		elseif param == keys.down then\\r\\\
			local cursorSet = setCursorMark\\r\\\
\\r\\\
			if holdingShift then\\r\\\
				cursorSet = setCursor\\r\\\
			end\\r\\\
\\r\\\
			-- Down\\r\\\
			if not bMenu then\\r\\\
				-- Move cursor down\\r\\\
				if nCompletion then\\r\\\
					-- Cycle completions\\r\\\
					nCompletion = nCompletion + 1\\r\\\
					if nCompletion > #tCompletions then\\r\\\
						nCompletion = 1\\r\\\
					end\\r\\\
					redrawLine(y)\\r\\\
\\r\\\
				elseif y < #tLines then\\r\\\
					-- Move cursor down\\r\\\
					--[[cursorSet(\\r\\\
						math.min( x, string.len( tLines[y + 1] ) + 1 ),\\r\\\
						y + 1\\r\\\
					)]]\\r\\\
\\r\\\
					local cx = getCursorX(y)\\r\\\
					local pos = cxToPos(y + 1, cx)\\r\\\
\\r\\\
					cursorSet(pos, y + 1)\\r\\\
				else\\r\\\
					cursorSet(#tLines[y] + 1, y)\\r\\\
				end\\r\\\
			end\\r\\\
\\r\\\
		elseif param == keys.tab then\\r\\\
			-- Tab\\r\\\
			if not bMenu and not bReadOnly then\\r\\\
				if nCompletion and x == string.len(tLines[y]) + 1 then\\r\\\
					-- Accept autocomplete\\r\\\
					acceptCompletion()\\r\\\
				else\\r\\\
					local msx, msy, mex, mey = getMarks()\\r\\\
\\r\\\
					for i = msy, mey do\\r\\\
						local line = tLines[i]\\r\\\
\\r\\\
						if holdingShift then\\r\\\
							-- Unindent line\\r\\\
							if line:sub(1, 1) == '\\\\t' then\\r\\\
								line = line:sub(2)\\r\\\
							end\\r\\\
						else\\r\\\
							-- Indent line\\r\\\
							if markExists() then\\r\\\
								line = '\\\\t' .. line\\r\\\
							else\\r\\\
								line = line:sub(1, x - 1) .. '\\\\t' .. line:sub(x)\\r\\\
							end\\r\\\
						end\\r\\\
\\r\\\
						tLines[i] = line\\r\\\
					end\\r\\\
\\r\\\
					if holdingShift then\\r\\\
						markX = math.max(1, markX - 1)\\r\\\
						setCursor(math.max(1, x - 1), y)\\r\\\
					else\\r\\\
						markX = markX + 1\\r\\\
						setCursor(x + 1, y)\\r\\\
					end\\r\\\
\\r\\\
					onUpdate()\\r\\\
					redrawText()\\r\\\
				end\\r\\\
			end\\r\\\
\\r\\\
		elseif param == keys.pageUp then\\r\\\
			local cursorSet = setCursorMark\\r\\\
\\r\\\
			if holdingShift then\\r\\\
				cursorSet = setCursor\\r\\\
			end\\r\\\
\\r\\\
			-- Page Up\\r\\\
			if not bMenu then\\r\\\
				-- Move up a page\\r\\\
				local newY\\r\\\
				if y - (h - 1) >= 1 then\\r\\\
					newY = y - (h - 1)\\r\\\
				else\\r\\\
					newY = 1\\r\\\
				end\\r\\\
				cursorSet(\\r\\\
					math.min( x, string.len( tLines[newY] ) + 1 ),\\r\\\
					newY\\r\\\
				)\\r\\\
			end\\r\\\
\\r\\\
		elseif param == keys.pageDown then\\r\\\
			local cursorSet = setCursorMark\\r\\\
\\r\\\
			if holdingShift then\\r\\\
				cursorSet = setCursor\\r\\\
			end\\r\\\
\\r\\\
			-- Page Down\\r\\\
			if not bMenu then\\r\\\
				-- Move down a page\\r\\\
				local newY\\r\\\
				if y + (h - 1) <= #tLines then\\r\\\
					newY = y + (h - 1)\\r\\\
				else\\r\\\
					newY = #tLines\\r\\\
				end\\r\\\
				local newX = math.min( x, string.len( tLines[newY] ) + 1 )\\r\\\
				cursorSet( newX, newY )\\r\\\
			end\\r\\\
\\r\\\
		elseif param == keys.home then\\r\\\
			local cursorSet = setCursorMark\\r\\\
\\r\\\
			if holdingShift then\\r\\\
				cursorSet = setCursor\\r\\\
			end\\r\\\
\\r\\\
			-- Home\\r\\\
			if not bMenu then\\r\\\
				-- Move cursor to the beginning\\r\\\
				if x > 1 then\\r\\\
					cursorSet(1,y)\\r\\\
				end\\r\\\
			end\\r\\\
\\r\\\
		elseif param == keys[\\\"end\\\"] then\\r\\\
			local cursorSet = setCursorMark\\r\\\
\\r\\\
			if holdingShift then\\r\\\
				cursorSet = setCursor\\r\\\
			end\\r\\\
\\r\\\
			-- End\\r\\\
			if not bMenu then\\r\\\
				-- Move cursor to the end\\r\\\
				local nLimit = string.len( tLines[y] ) + 1\\r\\\
				if x < nLimit then\\r\\\
					cursorSet( nLimit, y )\\r\\\
				end\\r\\\
			end\\r\\\
\\r\\\
		elseif param == keys.left then\\r\\\
			local cursorSet = setCursorMark\\r\\\
\\r\\\
			if holdingShift then\\r\\\
				cursorSet = setCursor\\r\\\
			end\\r\\\
\\r\\\
			-- Left\\r\\\
			if not bMenu then\\r\\\
				if x > 1 then\\r\\\
					-- Move cursor left\\r\\\
					cursorSet( x - 1, y )\\r\\\
				elseif x==1 and y>1 then\\r\\\
					cursorSet( string.len( tLines[y-1] ) + 1, y - 1 )\\r\\\
				end\\r\\\
			else\\r\\\
				-- Move menu left\\r\\\
				nMenuItem = nMenuItem - 1\\r\\\
				if nMenuItem < 1 then\\r\\\
					nMenuItem = #tMenuItems\\r\\\
				end\\r\\\
				redrawMenu()\\r\\\
			end\\r\\\
\\r\\\
		elseif param == keys.right then\\r\\\
			local cursorSet = setCursorMark\\r\\\
\\r\\\
			if holdingShift then\\r\\\
				cursorSet = setCursor\\r\\\
			end\\r\\\
\\r\\\
			-- Right\\r\\\
			if not bMenu then\\r\\\
				local nLimit = string.len( tLines[y] ) + 1\\r\\\
				if x < nLimit then\\r\\\
					-- Move cursor right\\r\\\
					cursorSet( x + 1, y )\\r\\\
				elseif nCompletion and x == string.len(tLines[y]) + 1 then\\r\\\
					-- Accept autocomplete\\r\\\
					acceptCompletion()\\r\\\
				elseif x==nLimit and y<#tLines then\\r\\\
					-- Go to next line\\r\\\
					cursorSet( 1, y + 1 )\\r\\\
				end\\r\\\
			else\\r\\\
				-- Move menu right\\r\\\
				nMenuItem = nMenuItem + 1\\r\\\
				if nMenuItem > #tMenuItems then\\r\\\
					nMenuItem = 1\\r\\\
				end\\r\\\
				redrawMenu()\\r\\\
			end\\r\\\
\\r\\\
		elseif param == keys.delete then\\r\\\
			-- Delete\\r\\\
			if not bMenu and not bReadOnly then\\r\\\
				if markExists() then\\r\\\
					deleteMarked()\\r\\\
				else\\r\\\
					local nLimit = string.len( tLines[y] ) + 1\\r\\\
					if x < nLimit then\\r\\\
						local sLine = tLines[y]\\r\\\
						tLines[y] = string.sub(sLine,1,x-1) .. string.sub(sLine,x+1)\\r\\\
					elseif y<#tLines then\\r\\\
						tLines[y] = tLines[y] .. tLines[y+1]\\r\\\
						table.remove( tLines, y+1 )\\r\\\
					end\\r\\\
				end\\r\\\
\\r\\\
				onUpdate()\\r\\\
				recomplete()\\r\\\
				redrawText()\\r\\\
			end\\r\\\
\\r\\\
		elseif param == keys.backspace then\\r\\\
			-- Backspace\\r\\\
			if not bMenu and not bReadOnly then\\r\\\
				if markExists() then\\r\\\
					deleteMarked()\\r\\\
				else\\r\\\
					if x > 1 then\\r\\\
						-- Remove character\\r\\\
						local sLine = tLines[y]\\r\\\
						tLines[y] = string.sub(sLine,1,x-2) .. string.sub(sLine,x)\\r\\\
						setCursorMark( x - 1, y )\\r\\\
					elseif y > 1 then\\r\\\
						-- Remove newline\\r\\\
						local sPrevLen = string.len( tLines[y-1] )\\r\\\
						tLines[y-1] = tLines[y-1] .. tLines[y]\\r\\\
						table.remove( tLines, y )\\r\\\
						setCursorMark( sPrevLen + 1, y - 1 )\\r\\\
					end\\r\\\
				end\\r\\\
\\r\\\
				onUpdate()\\r\\\
				recomplete()\\r\\\
				redrawText()\\r\\\
			end\\r\\\
\\r\\\
		elseif param == keys.enter then\\r\\\
			-- Enter\\r\\\
			if not bMenu and not bReadOnly then\\r\\\
				deleteMarked()\\r\\\
\\r\\\
				-- Newline\\r\\\
				local sLine = tLines[y]\\r\\\
				local _,tabs=string.find(sLine,\\\"^[\\\\t]+\\\")\\r\\\
				if not tabs then\\r\\\
					tabs=0\\r\\\
				end\\r\\\
				tLines[y] = string.sub(sLine,1,x-1)\\r\\\
				table.insert( tLines, y+1, string.rep('\\\\t',tabs)..string.sub(sLine,x) )\\r\\\
				onUpdate()\\r\\\
				setCursorMark( tabs + 1, y + 1 )\\r\\\
				redrawText()\\r\\\
\\r\\\
			elseif bMenu then\\r\\\
				-- Menu selection\\r\\\
				doMenuItem( nMenuItem )\\r\\\
\\r\\\
			end\\r\\\
\\r\\\
		elseif (param == keys.leftCtrl or param == keys.rightCtrl) and not param2 then\\r\\\
			-- Menu toggle\\r\\\
			bMenu = not bMenu\\r\\\
			if bMenu then\\r\\\
				term.setCursorBlink( false )\\r\\\
			else\\r\\\
				term.setCursorBlink( true )\\r\\\
			end\\r\\\
			redrawMenu()\\r\\\
\\r\\\
		elseif param == 42 then\\r\\\
			holdingShift = true\\r\\\
		end\\r\\\
\\r\\\
	elseif sEvent == 'key_up' then\\r\\\
		if param == 42 then\\r\\\
			holdingShift = false\\r\\\
		end\\r\\\
\\r\\\
	elseif sEvent == \\\"char\\\" then\\r\\\
		if not bMenu and not bReadOnly then\\r\\\
			deleteMarked()\\r\\\
\\r\\\
			-- Input text\\r\\\
			local sLine = tLines[y]\\r\\\
			tLines[y] = string.sub(sLine,1,x-1) .. param .. string.sub(sLine,x)\\r\\\
			onUpdate()\\r\\\
			setCursorMark( x + 1, y )\\r\\\
\\r\\\
		elseif bMenu then\\r\\\
			-- Select menu items\\r\\\
			for n,sMenuItem in ipairs( tMenuItems ) do\\r\\\
				if string.lower(string.sub(sMenuItem,1,1)) == string.lower(param) then\\r\\\
					doMenuItem( n )\\r\\\
					break\\r\\\
				end\\r\\\
			end\\r\\\
		end\\r\\\
\\r\\\
	elseif sEvent == \\\"paste\\\" then\\r\\\
		if not bMenu and not bReadOnly then\\r\\\
			-- Input text\\r\\\
			--[[local sLine = tLines[y]\\r\\\
			tLines[y] = string.sub(sLine,1,x-1) .. param .. string.sub(sLine,x)\\r\\\
			onUpdate()\\r\\\
			setCursorMark( x + string.len( param ), y )]]\\r\\\
\\r\\\
			--[[deleteMarked()\\r\\\
\\r\\\
			local newX, newY = x, y\\r\\\
\\r\\\
			for i = 1, #param do\\r\\\
				local char = param:sub(i, i)\\r\\\
\\r\\\
				if char == '\\\\n' then\\r\\\
					local rest = tLines[newY]:sub(newX)\\r\\\
					tLines[newY] = tLines[newY]:sub(1, newX - 1)\\r\\\
\\r\\\
					table.insert(tLines, rest, newY + 1)\\r\\\
\\r\\\
					newY = newY + 1\\r\\\
					newX = 1\\r\\\
				else\\r\\\
					local line = tLines[newY]\\r\\\
\\r\\\
					line = line:sub(1, newX - 1) .. char .. line:sub(newX)\\r\\\
\\r\\\
					tLines[newY] = line\\r\\\
					newX = newX + 1\\r\\\
				end\\r\\\
			end\\r\\\
\\r\\\
			onUpdate()\\r\\\
			setCursorMark(newX, newY)]]\\r\\\
\\r\\\
			local oldvClipboard = vClipboard\\r\\\
			vClipboard = param\\r\\\
			tMenuFuncs.VPaste()\\r\\\
			redrawMenu()\\r\\\
			vClipboard = oldvClipboard\\r\\\
		end\\r\\\
\\r\\\
	elseif sEvent == \\\"mouse_click\\\" then\\r\\\
		local cursorSet = setCursorMark\\r\\\
\\r\\\
		if holdingShift then\\r\\\
			cursorSet = setCursor\\r\\\
		end\\r\\\
\\r\\\
		if not bMenu then\\r\\\
			if param == 1 then\\r\\\
				-- Left click\\r\\\
				local cx,cy = param2, param3\\r\\\
				if cy < h then\\r\\\
					local tx, ty = cx + scrollX, cy + scrollY\\r\\\
					local newX, newY\\r\\\
\\r\\\
					if ty <= #tLines then\\r\\\
						newY = math.min(#tLines, math.max(ty, 1))\\r\\\
						tx = cxToPos(ty, tx)\\r\\\
						newX = math.min(tLines[newY]:len() + 1, math.max(1, tx))\\r\\\
					else\\r\\\
						newY = #tLines\\r\\\
						newX = #tLines[newY] + 1\\r\\\
					end\\r\\\
\\r\\\
					cursorSet(newX, newY)\\r\\\
				end\\r\\\
			end\\r\\\
		end\\r\\\
\\r\\\
	elseif sEvent == \\\"mouse_drag\\\" then\\r\\\
		if not bMenu then\\r\\\
			if param == 1 then\\r\\\
				-- Left click\\r\\\
				local cx,cy = param2, param3\\r\\\
				if cy < h then\\r\\\
					local tx, ty = cx + scrollX, cy + scrollY\\r\\\
					local newX, newY\\r\\\
\\r\\\
					if ty <= #tLines then\\r\\\
						newY = math.min(#tLines, math.max(ty, 1))\\r\\\
						tx = cxToPos(ty, tx)\\r\\\
						newX = math.min(tLines[newY]:len() + 1, math.max(1, tx))\\r\\\
					else\\r\\\
						newY = #tLines\\r\\\
						newX = #tLines[newY] + 1\\r\\\
					end\\r\\\
\\r\\\
					setCursor(newX, newY)\\r\\\
				end\\r\\\
			end\\r\\\
		end\\r\\\
\\r\\\
	elseif sEvent == \\\"mouse_scroll\\\" then\\r\\\
		if not bMenu then\\r\\\
			if param == -1 then\\r\\\
				-- Scroll up\\r\\\
				if scrollY > 0 then\\r\\\
					-- Move cursor up\\r\\\
					scrollY = scrollY - 1\\r\\\
					redrawText()\\r\\\
				end\\r\\\
\\r\\\
			elseif param == 1 then\\r\\\
				-- Scroll down\\r\\\
				local nMaxScroll = #tLines - (h-1)\\r\\\
				if scrollY < nMaxScroll then\\r\\\
					-- Move cursor down\\r\\\
					scrollY = scrollY + 1\\r\\\
					redrawText()\\r\\\
				end\\r\\\
\\r\\\
			end\\r\\\
		end\\r\\\
\\r\\\
	elseif sEvent == \\\"term_resize\\\" then\\r\\\
		w,h = term.getSize()\\r\\\
		setCursor( x, y )\\r\\\
		redrawMenu()\\r\\\
		redrawText()\\r\\\
\\r\\\
	end\\r\\\
end\\r\\\
\\r\\\
-- Cleanup\\r\\\
term.clear()\\r\\\
term.setCursorBlink( false )\\r\\\
term.setCursorPos( 1, 1 )\",\
    [ \"bin/config.sh\" ] = \"-- config command tool.\\\
args = {...}\\\
local config = args[1]\\\
local setting = args[2]\\\
\\\
-- select the functions\\\
if config == \\\"login\\\" then\\\
	if setting == \\\"local\\\" or setting == \\\"network\\\" or setting == \\\"disabled\\\" then\\\
		minux.setconfig(config , setting)\\\
	else\\\
		print(\\\"Invalid input, try 'man config'\\\")\\\
	end\\\
elseif config == \\\"encrypt\\\" then\\\
	if setting == \\\"enabled\\\" or setting == \\\"disabled\\\" then\\\
		minux.setconfig(config, setting)\\\
	else\\\
		print(\\\"invalid input, try man config\\\")\\\
	end\\\
elseif config == \\\"clearlogin\\\" then\\\
	if setting == \\\"enabled\\\" or setting == \\\"disabled\\\" then\\\
		minux.setconfig(config, setting)\\\
	else\\\
		print(\\\"invalid input, try man config\\\")\\\
	end\\\
elseif config == \\\"mapcleanup\\\" then\\\
	if setting == \\\"enabled\\\" or setting == \\\"disabled\\\" then\\\
		minux.setconfig(config, setting)\\\
	else\\\
		print(\\\"invalid input, try man config\\\")\\\
	end\\\
elseif config == \\\"mapcleanup\\\" then\\\
	if setting == \\\"enabled\\\" or setting == \\\"disabled\\\" then\\\
		minux.setconfig(config, setting)\\\
	else\\\
		print(\\\"invalid input, try man config\\\")\\\
	end\\\
elseif config == \\\"update\\\" then \\\
	if setting == \\\"always\\\" or setting == \\\"enabled\\\" or setting == \\\"disabled\\\" then\\\
		minux.setconfig(config , setting)\\\
	else\\\
		print(\\\"Invalid input, try 'man config'\\\")\\\
	end\\\
elseif config == \\\"menu\\\"  or config == \\\"ui\\\" then\\\
	if setting == \\\"menu\\\" or setting == \\\"prompt\\\" or setting == \\\"workspace\\\" or setting == \\\"craftos\\\" then\\\
		minux.setconfig(config,setting)\\\
	else\\\
		print(\\\"Invalid input, try 'man config'\\\")\\\
	end\\\
elseif config == \\\"welcome\\\" then\\\
	if setting == \\\"disabled\\\" or setting == \\\"enabled\\\" then\\\
		minux.setconfig(config,setting)\\\
	else\\\
		print(\\\"Invalid input, try 'man config'\\\")\\\
	end\\\
elseif config == \\\"crashhandler\\\" then\\\
	if setting == \\\"disabled\\\" or setting == \\\"enabled\\\" then\\\
		minux.setconfig(config,setting)\\\
	else\\\
		print(\\\"Invalid input, try 'man config'\\\")\\\
	end\\\
elseif config == \\\"debug\\\" then\\\
	if setting == \\\"disabled\\\" or setting == \\\"enabled\\\" or setting == \\\"logging\\\" or setting == \\\"full\\\" then\\\
		minux.setconfig(config,setting)\\\
	else\\\
		print(\\\"Invalid input, try 'man config'\\\")\\\
	end\\\
elseif config == \\\"network\\\" then\\\
	if setting == \\\"disabled\\\" or setting == \\\"enabled\\\" then\\\
		minux.setconfig(config, setting)\\\
	else\\\
		print(\\\"Invalid input, try 'man config'\\\")\\\
	end\\\
elseif config == nil and apt.checkinstall(\\\"menu\\\") == true then\\\
	shell.run(\\\"/etc/minux-main/menu/config.sys\\\")\\\
else\\\
	print(\\\"Invalid input, try 'man config'\\\")\\\
end\\\
\",\
    [ \"gbin/config.exe\" ] = \"-- just a way for a gui to identify working apps it can use.\\r\\\
shell.run(\\\"/bin/config.sh\\\")\",\
    [ \"etc/man/workspace.man\" ] = \"Workspace, made by LDDestroier\\r\\\
see https://forums.computercraft.cc/index.php?topic=661.new#new for more\\r\\\
