    [ \"boot/init.sys\" ] = \"local bash = \\\"/etc/minux-main/workspace/shell.lua\\\"\\r\\\
local oldshell = \\\"/rom/programs/shell.lua\\\"\\r\\\
local crashstage = 0\\r\\\
local cursorhor, cursorver = term.getCursorPos()\\r\\\
function getcrashhandler(stage)\\r\\\
	local stagestate = 0\\r\\\
	if fs.exists(\\\"/temp/minux/boot/fail\\\"..stage..\\\".tmp\\\") then\\r\\\
		local tempfile = fs.open(\\\"/temp/minux/boot/fail\\\"..stage..\\\".tmp\\\" ,\\\"r\\\")\\r\\\
		stagestate = tempfile.readLine()\\r\\\
		tempfile.close()\\r\\\
	end\\r\\\
	return stagestate\\r\\\
end\\r\\\
function setcrashhandler(stage, value)\\r\\\
	local tempfile = fs.open(\\\"/temp/minux/boot/fail\\\"..stage..\\\".tmp\\\" ,\\\"w\\\")\\r\\\
	tempfile.writeLine(value)\\r\\\
	tempfile.close()\\r\\\
end\\r\\\
function repairshell(stage)\\r\\\
	term.clear()\\r\\\
	term.setCursorPos(1,1)\\r\\\
	if stage == \\\"1\\\" or stage == 1 then\\r\\\
		print(\\\"Kernel panic\\\")\\r\\\
	else\\r\\\
		print(\\\"Minux-V:\\\".._G.version..\\\" Init fail\\\")\\r\\\
	end\\r\\\
	print(\\\"Init stage:\\\"..stage)\\r\\\
	if stage == 4 or stage == \\\"4\\\" then\\r\\\
		print(\\\" \\\")\\r\\\
		print(\\\"Causes:\\\")\\r\\\
		print(\\\"1) your UI or bootup program is broken\\\")\\r\\\
		print(\\\"2) you shut down the computer with the button\\\")\\r\\\
		print(\\\"3) the Minecraft Chunk reloaded\\\")\\r\\\
		print(\\\"you can disable this stage using 'config'\\\")\\r\\\
	end\\r\\\
	print(\\\" \\\")\\r\\\
	print(\\\"hit enter to launch repair shell\\\")\\r\\\
	read()\\r\\\
	setcrashhandler(\\\"1\\\",\\\"0\\\")\\r\\\
	shell.run(oldshell)\\r\\\
end\\r\\\
function screenpos(cursorver)\\r\\\
	if pocket or turtle then\\r\\\
		term.setCursorPos(15,cursorver)\\r\\\
	else\\r\\\
		term.setCursorPos(40,cursorver)\\r\\\
	end\\r\\\
end\\r\\\
if pocket or turtle then\\r\\\
	print(\\\"-----------Minux----------\\\")\\r\\\
else\\r\\\
	print(\\\"--------------------Minux--------------------------\\\")\\r\\\
end\\r\\\
crashstage = getcrashhandler(\\\"1\\\")\\r\\\
if crashstage == \\\"2\\\" or crashstage == 2 then\\r\\\
	setcrashhandler(\\\"1\\\",\\\"0\\\")\\r\\\
	repairshell(\\\"1\\\")\\r\\\
else\\r\\\
	crashstage = crashstage + 1\\r\\\
	setcrashhandler(\\\"1\\\",crashstage)\\r\\\
end\\r\\\
cursorhor, cursorver = term.getCursorPos()\\r\\\
print(\\\"Kernel:\\\")\\r\\\
os.loadAPI(\\\"/etc/api/minux\\\")\\r\\\
os.loadAPI(\\\"/etc/api/apt\\\")\\r\\\
os.loadAPI(\\\"/etc/minux-main/sys/menu.lua\\\")\\r\\\
expectfile = \\\"/rom/modules/main/cc/expect.lua\\\"\\r\\\
_G.expect = dofile(expectfile)\\r\\\
if term.isColor() then\\r\\\
	term.setTextColor(colors.green)\\r\\\
end\\r\\\
local dbfile = \\\"/etc/apt/list/minux-main.db\\\"\\r\\\
if fs.exists(dbfile) then\\r\\\
	local templinenr = minux.findline(dbfile,\\\"version=\\\")\\r\\\
	local templinedata = minux.printline(dbfile,templinenr)\\r\\\
	local result = string.sub(templinedata, 9)\\r\\\
	_G.version = result\\r\\\
else\\r\\\
	_G.version = \\\"Cleaninstall\\\"\\r\\\
end\\r\\\
screenpos(cursorver)\\r\\\
print(\\\"[V:\\\".._G.version..\\\"]\\\")\\r\\\
shell.run(\\\"/boot/alias.ls\\\")\\r\\\
if term.isColor() then term.setTextColor(colors.white) end\\r\\\
cursorhor, cursorver = term.getCursorPos()\\r\\\
print(\\\"Sanitycheck:\\\")\\r\\\
minux.sanitycheck()\\r\\\
if term.isColor() then\\r\\\
	term.setTextColor(colors.green)\\r\\\
end\\r\\\
screenpos(cursorver)\\r\\\
print(\\\"[Cleared]\\\")\\r\\\
if term.isColor() then\\r\\\
	term.setTextColor(colors.white)\\r\\\
end\\r\\\
cursorhor, cursorver = term.getCursorPos()\\r\\\
print(\\\"Modem:\\\")\\r\\\
_G.modemside = minux.perfind(\\\"modem\\\")\\r\\\
if term.isColor() then\\r\\\
	if _G.modemside ~= \\\"NONE\\\" then\\r\\\
		term.setTextColor(colors.green)\\r\\\
	else\\r\\\
		term.setTextColor(colors.red)\\r\\\
	end\\r\\\
end\\r\\\
screenpos(cursorver)\\r\\\
print(\\\"[\\\".._G.modemside..\\\"]\\\")\\r\\\
if term.isColor() then\\r\\\
