print(\\\"Monitor:\\\")\\r\\\
_G.monitorside = minux.perfind(\\\"monitor\\\")\\r\\\
if term.isColor() then\\r\\\
	if _G.monitorside ~= \\\"NONE\\\" then\\r\\\
		term.setTextColor(colors.green)\\r\\\
