cursorhor, cursorver = term.getCursorPos()\\r\\\
print(\\\"Printer:\\\")\\r\\\
_G.printerside = minux.perfind(\\\"printer\\\")\\r\\\
if term.isColor() then\\r\\\
	if _G.printerside ~= \\\"NONE\\\" then\\r\\\
