cursorhor, cursorver = term.getCursorPos()\\r\\\
print(\\\"Speaker:\\\")\\r\\\
_G.speakerside = minux.perfind(\\\"speaker\\\")\\r\\\
if term.isColor() then\\r\\\
	if _G.speakerside ~= \\\"NONE\\\" then\\r\\\
		term.setTextColor(colors.green)\\r\\\
	else\\r\\\
		term.setTextColor(colors.red)\\r\\\
	end\\r\\\
end\\r\\\
screenpos(cursorver)\\r\\\
print(\\\"[\\\".._G.speakerside..\\\"]\\\")\\r\\\
if term.isColor() then\\r\\\
	term.setTextColor(colors.white)\\r\\\
end\\r\\\
_G.server = \\\"[none]\\\"\\r\\\
if minux.getconfig(\\\"network\\\") == \\\"enabled\\\" then\\r\\\
	local cursorhor, cursorver = term.getCursorPos()\\r\\\
	print(\\\"DHCP:\\\")\\r\\\
	shell.run(\\\"/boot/network/dhcp.sys\\\")\\r\\\
	screenpos(cursorver)\\r\\\
	if term.isColor() then\\r\\\
		if _G.server == \\\"[none]\\\" then\\r\\\
			term.setTextColor(colors.red)\\r\\\
		else\\r\\\
			term.setTextColor(colors.green)\\r\\\
		end\\r\\\
	end\\r\\\
	if server ~= \\\"[none]\\\" then\\r\\\
		print(\\\"[\\\".._G.server..\\\"]\\\")\\r\\\
	else\\r\\\
		print(_G.server)\\r\\\
	end\\r\\\
	if term.isColor() then\\r\\\
		term.setTextColor(colors.white)\\r\\\
	end\\r\\\
end\\r\\\
cursorhor, cursorver = term.getCursorPos()\\r\\\
print(\\\"Crashhandler:\\\")\\r\\\
local temp = minux.getconfig(\\\"crashhandler\\\")\\r\\\
if term.isColor() then\\r\\\
	if temp == \\\"enabled\\\" then\\r\\\
		term.setTextColor(colors.green)\\r\\\
	else\\r\\\
		term.setTextColor(colors.red)\\r\\\
	end\\r\\\
end\\r\\\
screenpos(cursorver)\\r\\\
print(\\\"[\\\"..temp..\\\"]\\\")\\r\\\
if term.isColor() then\\r\\\
	term.setTextColor(colors.white)\\r\\\
end\\r\\\
setcrashhandler(\\\"1\\\",\\\"0\\\")\\r\\\
crashstage = getcrashhandler(\\\"2\\\")\\r\\\
if crashstage == \\\"2\\\" or crashstage == 2 then\\r\\\
	setcrashhandler(\\\"2\\\",\\\"0\\\")\\r\\\
	repairshell(\\\"2\\\")\\r\\\
else\\r\\\
	crashstage = crashstage + 1\\r\\\
	setcrashhandler(\\\"2\\\",crashstage)\\r\\\
end\\r\\\
local readdebug = minux.getconfig(\\\"debug\\\")\\r\\\
_G.debugmode = readdebug\\r\\\
cursorhor, cursorver = term.getCursorPos()\\r\\\
print(\\\"Debug system:\\\")\\r\\\
if term.isColor() then\\r\\\
	if _G.debugmode == \\\"disabled\\\" then \\r\\\
		term.setTextColor(colors.green)\\r\\\
	else \\r\\\
		term.setTextColor(colors.red) \\r\\\
	end\\r\\\
end\\r\\\
screenpos(cursorver)\\r\\\
print(\\\"[\\\".._G.debugmode..\\\"]\\\")\\r\\\
if term.isColor() then term.setTextColor(colors.white) end\\r\\\
minux.debug(\\\"Debug system loaded\\\", \\\"minux\\\")\\r\\\
cursorhor, cursorver = term.getCursorPos()\\r\\\
print(\\\"login mode:\\\")\\r\\\
local temp = minux.getconfig(\\\"login\\\")\\r\\\
if term.isColor() then \\r\\\
	if temp ~= \\\"disabled\\\" then \\r\\\
		term.setTextColor(colors.green)\\r\\\
	else \\r\\\
		term.setTextColor(colors.red) \\r\\\
	end \\r\\\
end\\r\\\
screenpos(cursorver)\\r\\\
print(\\\"[\\\"..temp..\\\"]\\\")\\r\\\
if term.isColor() then term.setTextColor(colors.white) end\\r\\\
cursorhor, cursorver = term.getCursorPos()\\r\\\
print(\\\"UI mode:\\\")\\r\\\
local temp = minux.getconfig(\\\"ui\\\")\\r\\\
if term.isColor() then term.setTextColor(colors.green) end\\r\\\
screenpos(cursorver)\\r\\\
print(\\\"[\\\"..temp..\\\"]\\\")\\r\\\
if term.isColor() then term.setTextColor(colors.white) end\\r\\\
cursorhor, cursorver = term.getCursorPos()\\r\\\
print(\\\"updates:\\\")\\r\\\
local temp = minux.getconfig(\\\"update\\\")\\r\\\
if term.isColor() then\\r\\\
	if temp ~= \\\"disabled\\\" then \\r\\\
		term.setTextColor(colors.green)\\r\\\
	else \\r\\\
		term.setTextColor(colors.red) \\r\\\
	end\\r\\\
end\\r\\\
screenpos(cursorver)\\r\\\
print(\\\"[\\\"..temp..\\\"]\\\")\\r\\\
if term.isColor() then term.setTextColor(colors.white) end\\r\\\
local firstupdate = false\\r\\\
if fs.exists(\\\"/usr/minux-main/data/firstrun.db\\\") == false then\\r\\\
	firstupdate = true\\r\\\
	local tempfile = fs.open(\\\"/usr/minux-main/data/firstrun.db\\\",\\\"w\\\")\\r\\\
	tempfile.writeLine(\\\"done\\\")\\r\\\
	tempfile.close()\\r\\\
end\\r\\\
_G.shell = shell\\r\\\
shell.run(\\\"/boot/network/update.sys\\\")\\r\\\
if fs.exists(\\\"/etc/server.sys\\\") then\\r\\\
	minux.debug(\\\"Starting server.sys\\\", \\\"minux\\\")\\r\\\
	if term.isColor() then\\r\\\
		shell.openTab(\\\"/etc/server.sys\\\")\\r\\\
	else \\r\\\
		shell.run(\\\"/etc/server.sys\\\") \\r\\\
	end\\r\\\
end\\r\\\
if fs.exists(\\\"/boot/addon.d\\\") then\\r\\\
	minux.debug(\\\"running addons\\\", \\\"minux\\\")\\r\\\
	shell.run(\\\"/boot/addon.d\\\")\\r\\\
end\\r\\\
setcrashhandler(\\\"2\\\",\\\"0\\\")\\r\\\
crashstage = getcrashhandler(\\\"3\\\")\\r\\\
if crashstage == \\\"2\\\" or crashstage == 2 then\\r\\\
	setcrashhandler(\\\"3\\\",\\\"0\\\")\\r\\\
	repairshell(\\\"3\\\")\\r\\\
else\\r\\\
	crashstage = crashstage + 1\\r\\\
	setcrashhandler(\\\"3\\\",crashstage)\\r\\\
end\\r\\\
minux.debug(\\\"running override.d\\\", \\\"minux\\\")\\r\\\
if fs.exists(\\\"/boot/override.d\\\") then shell.run(\\\"/boot/override.d\\\") end\\r\\\
minux.debug(\\\"resetting crash handler stage 3\\\",\\\"minux\\\")\\r\\\
setcrashhandler(\\\"3\\\",\\\"0\\\")\\r\\\
if minux.getconfig(\\\"crashhandler\\\") == \\\"enabled\\\" then\\r\\\
	crashstage = getcrashhandler(\\\"4\\\")\\r\\\
	if crashstage == \\\"2\\\" or crashstage == 2 then\\r\\\
		setcrashhandler(\\\"4\\\",\\\"0\\\")\\r\\\
		repairshell(\\\"4\\\")\\r\\\
	else\\r\\\
		crashstage = crashstage + 1\\r\\\
		setcrashhandler(\\\"4\\\",crashstage)\\r\\\
	end\\r\\\
end\\r\\\
local runoncefile = \\\"/boot/runonce.sh\\\"\\r\\\
if fs.exists(runoncefile) ~= true then\\r\\\
	local tmprunoncefile = fs.open(\\\"/boot/runonce.sh\\\",\\\"w\\\")\\r\\\
	minux.debug(\\\"init:clearing runonce\\\",\\\"minux\\\")\\r\\\
	tmprunoncefile.close()\\r\\\
end\\r\\\
local runoncetable = minux.readtable(runoncefile)\\r\\\
local runoncecount = 1\\r\\\
minux.debug(\\\"init:executing runonce\\\",\\\"minux\\\")\\r\\\
while runoncetable[runoncecount] ~= nil do\\r\\\
	minux.debug(\\\"init:\\\"..runoncetable[runoncecount],\\\"minux\\\")\\r\\\
	shell.run(runoncetable[runoncecount])\\r\\\
	runoncecount = runoncecount + 1\\r\\\
end\\r\\\
runoncefile = fs.open(\\\"/boot/runonce.sh\\\",\\\"w\\\")\\r\\\
minux.debug(\\\"init:clearing runonce\\\",\\\"minux\\\")\\r\\\
runoncefile.close()\\r\\\
minux.debug(\\\"reading menu settings\\\", \\\"minux\\\")\\r\\\
if pocket or turtle then\\r\\\
	print(\\\"--------------------------\\\")\\r\\\
else\\r\\\
	print(\\\"---------------------------------------------------\\\")\\r\\\
end\\r\\\
minux.debug(\\\"checking login settings\\\", \\\"minux\\\")\\r\\\
local temp = minux.getconfig(\\\"login\\\")\\r\\\
if temp ~= \\\"disabled\\\" then\\r\\\
	if fs.exists(\\\"/etc/minux-main/sys/menulogin.sys\\\") then\\r\\\
		if term.isColor() then\\r\\\
			if turtle then\\r\\\
				minux.debug(\\\"no gui login for turtle\\\")\\r\\\
			else\\r\\\
				minux.debug(\\\"running gui login for pc\\\")\\r\\\
				while _G.validlogin ~= true do\\r\\\
					term.setBackgroundColor(colors.black)\\r\\\
					term.setTextColor(colors.white)\\r\\\
					minux.debug(\\\"running menulogin.sys\\\", \\\"minux\\\")\\r\\\
					shell.run(\\\"/etc/minux-main/sys/menulogin.sys\\\")\\r\\\
				end\\r\\\
			end\\r\\\
		end\\r\\\
	end\\r\\\
    minux.debug(\\\"running login.sh\\\", \\\"minux\\\")\\r\\\
	if _G.validlogin ~= true then shell.run(\\\"/bin/login.sh\\\") end\\r\\\
	while _G.validlogin ~= true do\\r\\\
		minux.debug(\\\"login failed.\\\", \\\"minux\\\")\\r\\\
		print(\\\"Login failed, try again.\\\")\\r\\\
		sleep(2)\\r\\\
		shell.run(\\\"/bin/login.sh\\\")\\r\\\
	end\\r\\\
else\\r\\\
	minux.debug(\\\"login disabled\\\", \\\"minux\\\")\\r\\\
	_G.validlogin = true\\r\\\
	_G.admin = true\\r\\\
	_G.login = \\\"foo\\\"\\r\\\
	_G.masterpass = \\\"bar\\\"\\r\\\
	if fs.exists(\\\"/boot/autorun.ls\\\") == true then\\r\\\
		shell.run(\\\"/boot/autorun.ls\\\")\\r\\\
	end\\r\\\
end\\r\\\
minux.testcolor()\\r\\\
if firstupdate == true then\\r\\\
	term.clear()\\r\\\
	term.setCursorPos(1,1)\\r\\\
	print(\\\"First run detected, verifying installation.\\\")\\r\\\
	print(\\\"This process may take a while, the system will reboot when done.\\\")\\r\\\
	apt.update(\\\"-f\\\")\\r\\\
	apt.aliasbuild()\\r\\\
	apt.bootbuild()\\r\\\
	apt.autorunbuild()\\r\\\
	os.reboot()\\r\\\
end\\r\\\
if pocket or turtle then\\r\\\
	print(\\\"hit enter to start\\\")\\r\\\
else\\r\\\
	print(\\\"Welcome to Minux, Hit enter to start\\\")\\r\\\
end\\r\\\
local initput = read()\\r\\\
while initput ~= nil do\\r\\\
	if initput == \\\"bash\\\" then\\r\\\
		minux.debug(\\\"launching prompt\\\", \\\"minux\\\")\\r\\\
		shell.run(bash)\\r\\\
	elseif initput == \\\"update\\\" then\\r\\\
		apt.update(\\\"-f\\\")\\r\\\
		initput = read()\\r\\\
	elseif initput == \\\"reboot\\\" or initput == \\\"restart\\\" then\\r\\\
		minux.restart()\\r\\\
	elseif initput == \\\"halt\\\" or initput == \\\"shutdown\\\" then\\r\\\
		minux.halt()\\r\\\
	else\\r\\\
		initput = nil\\r\\\
	end\\r\\\
end\\r\\\
local menuchoice = minux.getconfig(\\\"ui\\\")\\r\\\
if menuchoice == \\\"menu\\\" then\\r\\\
	minux.debug(\\\"launching menu\\\", \\\"minux\\\")\\r\\\
	if fs.exists(\\\"/bin/minux.sh\\\") then shell.run(\\\"/bin/minux.sh\\\")\\r\\\
	else shell.run(bash) end\\r\\\
elseif menuchoice == \\\"prompt\\\" then\\r\\\
	minux.debug(\\\"launching prompt\\\", \\\"minux\\\")\\r\\\
	shell.run(bash)\\r\\\
elseif menuchoice == \\\"craftos\\\" then\\r\\\
	minux.debug(\\\"launching craftos\\\", \\\"minux\\\")\\r\\\
	shell.run(oldshell)\\r\\\
elseif menuchoice == \\\"workspace\\\" then\\r\\\
	minux.debug(\\\"launching workspace\\\", \\\"minux\\\")\\r\\\
	shell.run(\\\"/bin/workspace.sh\\\")\\r\\\
else\\r\\\
	shell.run(bash)\\r\\\
end\\r\\\
minux.debug(\\\"system crash restart\\\", \\\"minux\\\")\\r\\\
os.reboot()\\r\\\
\",\
    [ \"etc/minux-main/workspace/workspace.lua\" ] = \"--[[\\\
Workspace v2\\\
