-- end minux-main alias\\r\\\
\",\
    [ \"etc/man/usermod.man\" ] = \"Usermod, local user \\\
manager\\\
executable location:\\\
/bin/usermod.sh   \\\
alias:usermod\\\
usermod is part of the \\\
'minux-main' app.\\\
\\\
syntax: \\\
usermod action arg1 arg2\\\
eg:\\\"usermod add foo bar\\\"\\\
\\\
action options:\\\
add : adds a user, this\\\
must be followed by the\\\
username and password.\\\
\\\
del : Deletes a user, \\\
this must be followed by\\\
the username\\\
\\\
psw : changes a user's \\\
password, this must be\\\
followed by the username\\\
and password\\\
\\\
Usermod allows you to \\\
manage local user \\\
accounts,these accounts\\\
will be disabled when \\\
the system is set to \\\
network login. the \\\
'root' account is the \\\
only admin and cannot\\\
be deleted, no other \\\
user can be made admin.\\\
\\\
remember: local AUTH \\\
must store the user and\\\
password files on the \\\
local machine, making\\\
them accessable to \\\
anyone who can gain \\\
access to this computer\\\
do NOT use passwords \\\
that you also use on \\\
other services with \\\
local AUTH, the security\\\
this provides is minimal\\\
at best.\\\
\\\
important locations:\\\
/usr/local/auth/users \\\
- this is where user \\\
files are stored. for \\\
now passwords are not \\\
hashed.\",\
    [ \"etc/minux-main/welcome/mnx.nfp\" ] = \"\\\
   ffffffffffffffffffffff \\\
  ff00f00f0f00f0f0f0f0f0ff\\\
  ff0f0f0f0f0f00f0f0ff0fff\\\
  ff0fff0f0f0f00f000f0f0ff\\\
   ffffffffffffffffffffff \\\
\",\
    [ \"bin/halt.sh\" ] = \"minux.halt()\\\
\",\
    [ \"bin/useradd.sh\" ] = \"-- searches for user type and then tries to add users\\\
args = {...}\\\
local newusername = args[1]\\\
local newpassword = args[2]\\\
-- error catching\\\
if newpassword == nil or newpassword == \\\"\\\" then print(\\\"useradd:invalid input\\\") return 0 end\\\
\\\
-- first find out what type of network we have and if we have auth-client\\\
if fs.exists(\\\"/bin/auth-client.sh\\\") then\\\
	authexist = true\\\
end\\\
authtype = minux.logintype()\\\
if authtype == \\\"disabled\\\" then print(\\\"no login system in use\\\") return 0 end\\\
\\\
-- now we can run the function\\\
if authtype == \\\"network\\\" then\\\
	auth.useradd(newusername , newpassword)\\\
elseif authtype == \\\"local\\\" then\\\
	os.run({} , \\\"/bin/usermod.sh\\\" , \\\"add\\\" , newusername , newpassword)\\\
else\\\
	print(\\\"login disabled or broken\\\")\\\
end\",\
    [ \"gbin/login.exe\" ] = \"-- just a way for a gui to identify working apps it can use.\\r\\\
term.clear()\\r\\\
term.setCursorPos(1,1)\\r\\\
shell.run(\\\"/bin/login.sh\\\")\\r\\\
\",\
    [ \"etc/man/config.man\" ] = \"config - configuration \\\
editor tool\\\
executable location: \\\
'/bin/config.sh'   \\\
alias: 'config'\\\
config is part of the \\\
'minux-main' app config\\\
is used to change minux\\\
configuration\\\
\\\
syntax: \\\
'config type setting' \\\
\\\
eg: \\\
'config login network'\\\
\\\
options:\\\
-login setting| \\\
setting can be:\\\
\\\"network\\\", \\\"local\\\", \\\
\\\"disabled\\\"\\\
changes AUTH settings.\\\
\\\
-update setting| \\\
setting can be:\\\
\\\"always\\\", \\\"enabled\\\", \\\
\\\"disabled\\\".\\\
changes update on boot \\\
\\\
-ui setting | setting \\\
can be:\\\
\\\"menu\\\" , \\\"prompt\\\", \\\
\\\"workspace\\\" shows the \\\
menu screen on boot, a \\\
basic prompt or \\\
\\\"workspace\\\".\\\
\\\
-network setting | can\\\
\\\"enabled\\\"\\\
\\\"disabled\\\"\\\
turns dhcp search on\\\
boot on or off\\\
\\\
-debug setting | setting\\\
 can be: \\\"disabled\\\" , \\\
 \\\"enabled\\\" , \\\"logging\\\", \\\
 \\\"full\\\"\\\
sets debug mode, \\\
settings can be: \\\
\\\"enabled\\\" - increases \\\
user feedback\\\
\\\"logging\\\" - enables log\\\
 files. \\\
 \\\"full\\\" - does both \\\
 print and log.\\\
\\\"disabled\\\" - turns it all off\\\
\",\
    [ \"boot/alias.ls\" ] = \"-- default OS commands\\\
