shell.setAlias(\\\"apt\\\" , \\\"/bin/apt.sh\\\")\\\
shell.setAlias(\\\"login\\\" , \\\"/bin/login.sh\\\")\\\
shell.setAlias(\\\"cat\\\" , \\\"/bin/cat.sh\\\")\\\
shell.setAlias(\\\"usermod\\\" , \\\"/bin/usermod.sh\\\")\\\
shell.setAlias(\\\"man\\\" , \\\"/bin/man.sh\\\")\\\
shell.setAlias(\\\"makeboot\\\" , \\\"/bin/makeboot.sh\\\")\\\
\",\
    [ \"bin/userdel.sh\" ] = \"-- searches for user type and then tries to delete\\\
args = {...}\\\
local newusername = args[1]\\\
local newpassword = args[2]\\\
-- error catching\\\
if newusername == nil or newusername == \\\"\\\" then print(\\\"userdel:invalid input\\\") return 0 end\\\
\\\
-- first find out what type of network we have and if we have auth-client\\\
if fs.exists(\\\"/bin/auth-client.sh\\\") then\\\
	authexist = true\\\
end\\\
authtype = minux.logintype()\\\
if authtype == \\\"disabled\\\" then print(\\\"no login system in use\\\") return 0 end\\\
\\\
-- now we can run the function\\\
if authtype == \\\"network\\\" then\\\
	auth.userdel(newusername , newpassword)\\\
elseif authtype == \\\"local\\\" then\\\
	os.run({} , \\\"/bin/usermod.sh\\\" , \\\"del\\\" ,  newusername)\\\
else\\\
	print(\\\"login disabled or broken\\\")\\\
end\",\
    [ \"bin/newtab.sh\" ] = \"--newtab script\\\
print(\\\"Opening new tab\\\")\\\
if term.isColor then shell.openTab(\\\"/etc/minux-main/workspace/workspace.lua\\\")\\\
else print(\\\"Advanced computers only\\\") end\\\
\",\
    [ \"bin/bash.sh\" ] = \"-- bash shell launcher\\\
args = {...}\\\
local command = args[1]\\\
local txtcolor = args[2]\\\
local bgcolor = args[3]\\\
local prmcolor = args[4]\\\
\\\
if args[1] == \\\"setcolor\\\" then\\\
	minux.bashcolor(txtcolor, bgcolor, prmcolor)\\\
else\\\
	shell.run(\\\"/etc/minux-main/workspace/shell.lua\\\", command)\\\
end\\\
\",\
    [ \"gbin/useradd.exe\" ] = \"-- gbin useradd, made to be run without input\\r\\\
term.clear()\\r\\\
term.setCursorPos(1,1)\\r\\\
print(\\\"Adding new user\\\")\\r\\\
\\r\\\
